                            className={`h-1 rounded-full transition-all duration-300 cursor-pointer ${activeSlide === idx ? 'w-4 bg-white' : 'w-1 bg-white/30'}`}
                        ></div>
                    ))}
                </div>
            </div>
        </div>

        {/* 4-Grid Menu */}
        <div className="px-5">
            <h3 className="text-slate-500 font-bold text-xs uppercase tracking-widest mb-3 ml-1">Quick Access</h3>
            <div className="grid grid-cols-2 gap-3">
                {/* Infinity Practice */}
                <div onClick={onOpenInfinity} className="bg-white dark:bg-gradient-to-br dark:from-purple-800 dark:to-indigo-900 p-4 rounded-3xl shadow-sm hover:shadow-md dark:shadow-none active:scale-95 transition-transform flex flex-col items-center justify-center text-center h-32 cursor-pointer relative overflow-hidden group border border-slate-200 dark:border-purple-800/30">
                    <div className="absolute top-0 right-0 w-20 h-20 bg-purple-500/10 dark:bg-white/5 rounded-full blur-xl -mr-5 -mt-5"></div>
                    <div className="w-10 h-10 bg-purple-100 dark:bg-white/10 backdrop-blur-sm rounded-xl flex items-center justify-center mb-2 text-purple-600 dark:text-purple-200 border border-purple-200 dark:border-white/10">
                        <i className="fa-solid fa-infinity text-xl"></i>
