                     <div className="absolute top-0 left-0 w-20 h-20 bg-blue-500/10 dark:bg-white/5 rounded-full blur-xl -ml-5 -mt-5"></div>
                    <div className="w-10 h-10 bg-blue-100 dark:bg-white/10 backdrop-blur-sm rounded-xl flex items-center justify-center mb-2 text-blue-600 dark:text-blue-200 border border-blue-200 dark:border-white/10">
