interface PYQDashboardProps {
  isOpen: boolean;
  onClose: () => void;
  initialTab?: 'objective' | 'subjective';
  instantOpen?: boolean;
  onSelectYear: (subject: string, year: number, type: 'objective' | 'subjective') => void;
}

export const PYQDashboard: React.FC<PYQDashboardProps> = ({ 
    isOpen, 
    onClose, 
    onSelectYear, 
    initialTab = 'objective', 
    instantOpen = false 
}) => {
  const [activeTab, setActiveTab] = useState<'objective' | 'subjective'>(initialTab);
  const [selectedSubject, setSelectedSubject] = useState<string | null>(null);

  useEffect(() => {
    if (isOpen) {
      setActiveTab(initialTab);
      setSelectedSubject(null);
    }
  }, [isOpen, initialTab]);

  // Priority: Close Popup -> Switch to Objective -> Close Modal
  const handleAppBack = () => {
    if (selectedSubject) {
      setSelectedSubject(null);
      return true;
    }
    if (activeTab === 'subjective') {
      setActiveTab('objective');
      return true;
    }
    onClose();
    return true;
  };

  useBackHandler(handleAppBack, isOpen);

  const handleSubjectClick = (subject: string) => {
    setSelectedSubject(subject);
  };

  const handleYearClick = (year: number) => {
    if (selectedSubject) {
      onSelectYear(selectedSubject, year, activeTab);
    }
  };

  return (
    <AnimatePresence>
        {isOpen && (
            <>
                <motion.div 
                    initial={{ opacity: instantOpen ? 0.5 : 0 }} 
                    animate={{ opacity: 0.5 }}
                    exit={{ opacity: 0 }}
                    onClick={onClose}
                    className="fixed inset-0 bg-black z-40" 
                />

                <motion.div
                    initial={{ x: instantOpen ? 0 : "100%" }}
                    animate={{ x: 0 }}
                    exit={{ x: "100%" }}
                    transition={{ type: "spring", damping: 30, stiffness: 300 }}
                    className="fixed inset-y-0 right-0 w-full max-w-md bg-white dark:bg-slate-950 z-50 shadow-2xl flex flex-col h-[100dvh] overflow-hidden font-sans text-slate-900 dark:text-white transition-colors duration-300"
                >
                    <div className="absolute inset-0 z-0 opacity-[0.03] pointer-events-none" style={{ backgroundImage: 'radial-gradient(#888 1px, transparent 1px)', backgroundSize: '20px 20px' }}></div>

                    {/* Header with Safe Area (pt-safe-header) */}
                    <div className="px-5 pb-4 pt-safe-header bg-white/90 dark:bg-slate-950/90 backdrop-blur-sm border-b border-slate-200 dark:border-slate-800 flex items-center gap-3 sticky top-0 z-50 shadow-sm shrink-0 transition-colors">
                        <button onClick={handleAppBack} className="w-9 h-9 flex items-center justify-center rounded-full bg-slate-100 dark:bg-slate-900 text-slate-500 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-800 border border-slate-200 dark:border-slate-700 transition-colors -ml-1 active:scale-95">
                            <ChevronLeft size={24} />
