                        <div className="flex bg-slate-100 dark:bg-slate-900 p-1.5 rounded-2xl mb-8 border border-slate-200 dark:border-slate-800 shadow-sm isolate">
                        {(['objective', 'subjective'] as const).map((tab) => {
                            const isActive = activeTab === tab;
                            return (
                            <button
                                key={tab}
                                onClick={() => setActiveTab(tab)}
                                className={`flex-1 py-3 text-sm font-bold text-center relative transition-colors duration-200 ${isActive ? 'text-slate-900 dark:text-white' : 'text-slate-500 dark:text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                                style={{ WebkitTapHighlightColor: 'transparent' }}
                            >
                                {isActive && (
                                <motion.div
                                    layoutId="active-tab-pill"
                                    className="absolute inset-0 bg-white dark:bg-slate-700 rounded-xl shadow-md -z-10"
                                    transition={{ type: "spring", stiffness: 300, damping: 30 }}
                                />
                                )}
                                <span className="relative z-10 capitalize">{tab}</span>
                            </button>
                            );
                        })}
                        </div>

                        <h3 className="text-xs font-bold text-slate-500 dark:text-slate-500 uppercase tracking-widest mb-4 pl-1">Select Subject</h3>

                        <div className="relative min-h-[400px]"> 
                            <AnimatePresence mode='wait' initial={false}>
                                <motion.div
                                    key={activeTab}
                                    initial={{ x: 10, opacity: 0 }}
                                    animate={{ x: 0, opacity: 1 }}
                                    exit={{ x: -10, opacity: 0 }}
                                    transition={{ duration: 0.2 }}
                                    className="grid grid-cols-2 gap-4 w-full"
                                >
                                {subjectsList.map((sub) => (
                                    <div 
                                    key={sub.name} 
                                    onClick={() => handleSubjectClick(sub.name)}
                                    className={`bg-white dark:bg-slate-900 p-4 rounded-2xl border ${sub.border} shadow-sm hover:shadow-md hover:bg-slate-50 dark:hover:bg-slate-800 active:scale-[0.97] transition-all cursor-pointer flex flex-col justify-between h-40 group relative overflow-hidden`}
