                    </div>

                    <AnimatePresence>
                        {selectedSubject && (
                        <>
                            <motion.div 
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 0.3 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setSelectedSubject(null)}
                            className="absolute inset-0 bg-black z-40"
                            />

                            <motion.div
                            initial={{ y: "100%" }}
                            animate={{ y: 0 }}
                            exit={{ y: "100%" }}
                            transition={{ type: "spring", damping: 25, stiffness: 300 }}
                            className="absolute bottom-0 left-0 right-0 z-50 rounded-t-[2rem] overflow-hidden"
                            >
                            <div className="bg-white/95 dark:bg-slate-900/95 backdrop-blur-xl p-6 pb-safe border-t border-slate-200 dark:border-slate-800 shadow-[0_-10px_40px_rgba(0,0,0,0.2)]">
                                <div className="w-12 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full mx-auto mb-6 mt-2"></div>
                                <h3 className="text-xl font-black text-slate-900 dark:text-white mb-2 text-center">Select Year</h3>
                                <p className="text-slate-500 dark:text-slate-400 text-sm text-center mb-6">
                                Practice <span className="font-bold text-slate-700 dark:text-white capitalize">{activeTab}</span> PYQs for <span className="font-bold text-brand-600 dark:text-brand-400">{selectedSubject}</span>
                                </p>
                                <div className="flex overflow-x-auto gap-3 pb-6 px-2 hide-scrollbar snap-x">
