// Practice Screen
const PracticeScreen = ({ onSelectChapter, navigate, profile }: { onSelectChapter: (subject: string, chapter: string) => void, navigate: any, profile: Profile | null }) => {
    const [subjects, setSubjects] = useState<string[]>([]);
    const [searchParams, setSearchParams] = useSearchParams();
    const selectedSubject = searchParams.get('subject');

    const [chapters, setChapters] = useState<{en: string, hi: string, count: number}[]>([]);
    const [loading, setLoading] = useState(false);

    // 1. Caching Strategy for Subjects
    useEffect(() => {
      const cacheKey = 'subjects_cache';
      const cached = localStorage.getItem(cacheKey);

      // Instant Load from Cache
      if (cached) {
          setSubjects(JSON.parse(cached));
      }

      // Background Fetch & Update
      api.getSubjects().then(data => {
          setSubjects(data);
          localStorage.setItem(cacheKey, JSON.stringify(data));
      });
    }, []);

    // 2. Caching Strategy for Chapters (Strict Sorting handled in API)
    useEffect(() => {
      if (selectedSubject) {
          setLoading(true);
          const cacheKey = `chapters_cache_${selectedSubject}`;
          const cached = localStorage.getItem(cacheKey);

          // Instant Load from Cache
          if (cached) {
              setChapters(JSON.parse(cached));
              setLoading(false); 
          }

          // Background Fetch & Update
          api.getChapterStats(selectedSubject).then(data => {
              setChapters(data);
              localStorage.setItem(cacheKey, JSON.stringify(data));
              setLoading(false);
          });
      }
    }, [selectedSubject]);

    // Stack Logic: Chapter List -> Subject List -> Home
    const handleAppBack = () => {
        if (selectedSubject) {
            setSearchParams({}, { replace: true }); 
            return true; 
        } else {
            navigate('/'); 
            return true; 
        }
    };

    useBackHandler(handleAppBack, true); 

    return (
        <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-950 transition-colors duration-300">
            <div className="sticky top-0 z-50 px-5 pb-3 pt-safe-header bg-white dark:bg-slate-950 flex justify-between items-center border-b border-slate-200 dark:border-slate-800 shadow-sm transition-colors">
                <div className="flex items-center gap-3">
                    <button onClick={handleAppBack} className="text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors p-1 -ml-1 rounded-full active:bg-slate-100 dark:active:bg-slate-900">
                        <i className="fa-solid fa-chevron-left text-lg"></i>
                    </button>
                    <h2 className="text-xl font-black text-slate-900 dark:text-white">
                        {selectedSubject || 'Practice'}
                    </h2>
                </div>
                <div className="flex items-center gap-1 text-brand-500 dark:text-brand-400 font-black">
                    <i className="fa-solid fa-bolt text-xs"></i>
                    <span>{profile?.weekly_xp || 0}</span>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto hide-scrollbar p-5 pb-24 animate-fade-in bg-slate-50 dark:bg-slate-950 transition-colors">
                {!selectedSubject ? (
                    <>
                        <h2 className="text-2xl font-black text-slate-900 dark:text-white mb-6">Select <span className="text-brand-500">Subject</span></h2>
                        <div className="grid grid-cols-2 gap-4">
                            {subjects.map(sub => (
                                <div key={sub} onClick={() => setSearchParams({ subject: sub }, { replace: true })} className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm hover:shadow-md dark:shadow-none flex flex-col items-center justify-center gap-2 cursor-pointer active:scale-95 transition-transform hover:border-brand-500/50 group">
                                    <SubjectIcon subject={sub} />
                                    <span className="font-bold text-slate-600 dark:text-slate-300 text-sm group-hover:text-brand-600 dark:group-hover:text-white transition-colors">{sub}</span>
                                </div>
                            ))}
                        </div>
                    </>
                ) : (
                    <div className="space-y-3">
                        {loading && chapters.length === 0 ? (
                            <div className="text-center p-10 text-slate-500 text-sm font-bold animate-pulse">Loading chapters...</div>
                        ) : (
                            chapters.map((chap, idx) => (
                                <div key={idx} onClick={() => onSelectChapter(selectedSubject, chap.en)} className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm active:scale-[0.98] transition-transform flex items-center justify-between cursor-pointer hover:border-brand-500/30 group">
                                    <div>
                                        <h4 className="font-bold text-slate-700 dark:text-slate-200 text-sm group-hover:text-brand-600 dark:group-hover:text-brand-400 transition-colors">
                                            {idx + 1}. {chap.en}
                                        </h4>
                                        {chap.hi && <p className="text-xs text-slate-500 mt-1 font-medium">{chap.hi}</p>}
                                    </div>
                                    <div className="w-8 h-8 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-slate-400 dark:text-slate-500 group-hover:bg-brand-50 dark:group-hover:bg-brand-500/20 group-hover:text-brand-500 dark:group-hover:text-brand-400 transition-colors">
                                        <i className="fa-solid fa-chevron-right text-xs"></i>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

// Result Screen
const ResultScreen = ({ stats, onHome }: { stats: any, onHome: () => void }) => {
    if(!stats) return <div className="h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-950 text-slate-400">Loading Result...</div>;
    const score = stats.correct * 1; 
    return (
        <div className="h-[100dvh] overflow-y-auto bg-slate-50 dark:bg-slate-950 p-6 animate-slide-up pb-20 flex flex-col items-center justify-center text-center transition-colors duration-300">
            <div className="w-20 h-20 bg-brand-50 dark:bg-brand-500/10 rounded-full flex items-center justify-center mb-6 border border-brand-100 dark:border-brand-500/20">
                <i className="fa-solid fa-trophy text-4xl text-brand-600 dark:text-brand-500"></i>
            </div>
            <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-2">Test Completed</h2>
            <p className="text-slate-500 dark:text-slate-400 font-medium mb-8">Great job! Here is your performance.</p>

            <div className="bg-white dark:bg-slate-900 rounded-3xl p-8 w-full mb-8 border border-slate-200 dark:border-slate-800 shadow-sm">
                <div className="text-6xl font-black mb-2 text-brand-500 dark:text-brand-400">{score}</div>
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-6">Total Score</div>

                <div className="grid grid-cols-2 gap-4 w-full">
                    <div className="bg-slate-50 dark:bg-slate-950 p-4 rounded-2xl border border-slate-100 dark:border-slate-800"><p className="text-2xl font-black text-emerald-500 dark:text-emerald-400">{stats.correct}</p><p className="text-[10px] uppercase font-bold text-slate-500">Correct</p></div>
                    <div className="bg-slate-50 dark:bg-slate-950 p-4 rounded-2xl border border-slate-100 dark:border-slate-800"><p className="text-2xl font-black text-rose-500 dark:text-rose-400">{stats.wrong}</p><p className="text-[10px] uppercase font-bold text-slate-500">Wrong</p></div>
                </div>
            </div>

            <button onClick={onHome} className="w-full py-4 bg-brand-600 text-white font-bold rounded-xl shadow-lg hover:scale-[1.02] transition-transform shadow-brand-900/20">Return to Chapters</button>
        </div>
    );
};

// --- Main App Component ---
export default function App() {
  const [session, setSession] = useState<any>(null);
  const [isAppInitializing, setIsAppInitializing] = useState(true);

  // Theme State - Default 'light'
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    return (localStorage.getItem('raftaar-theme') as 'light' | 'dark') || 'light';
  });

  const [userProfile, setUserProfile] = useState<Profile | null>(null);
  const [activeTestQuestions, setActiveTestQuestions] = useState<Question[]>([]);
  const [activeSubject, setActiveSubject] = useState<string>('');
  const [testStats, setTestStats] = useState<any>(null);
  const [comingSoonTitle, setComingSoonTitle] = useState('');

  // Infinity Practice State
  const [isInfinityOpen, setInfinityOpen] = useState(false);
  const [infinityConfig, setInfinityConfig] = useState<{subject: string, chapters: string[]} | null>(null);
  const [infinityInstantOpen, setInfinityInstantOpen] = useState(false);

  // PYQ Modal State
  const [isPYQOpen, setPYQOpen] = useState(false);
  const [pyqInitialTab, setPyqInitialTab] = useState<'objective' | 'subjective'>('objective');
  const [instantOpen, setInstantOpen] = useState(false); 

  // Dashboard & Achievements Modals State
  const [isDashboardOpen, setDashboardOpen] = useState(false);
  const [isAchievementsOpen, setAchievementsOpen] = useState(false);

  // Double Back to Exit State
  const [exitAttempted, setExitAttempted] = useState(false);

  const navigate = useNavigate();
  const location = useLocation();
  const [searchParams, setSearchParams] = useSearchParams();

  // --- 1. GLOBAL STATUS BAR MANAGEMENT ---
  useStatusBar(theme);

  // --- THEME MANAGEMENT ---
  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove('light', 'dark');
    root.classList.add(theme);
    localStorage.setItem('raftaar-theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  // --- DOUBLE BACK TO EXIT LOGIC ---
  useBackHandler(() => {
    if (location.pathname === '/' && !isInfinityOpen && !isPYQOpen && !isDashboardOpen && !isAchievementsOpen) {
        if (exitAttempted) {
            return false; // Exit app
        } else {
            setExitAttempted(true);
            setTimeout(() => setExitAttempted(false), 2000); 
            return true; 
        }
    }
    return false; 
  }, location.pathname === '/' && !isInfinityOpen && !isPYQOpen && !isDashboardOpen && !isAchievementsOpen);

  useEffect(() => {
    let mounted = true;
    const restoreSession = async () => {
      try {
        const { data: { session }, error } = await supabase.auth.getSession();
        if (error) throw error;
        if (mounted && session) {
            setSession(session);
            fetchProfile(session.user.id).catch(console.error);
        }
      } catch (error) {
        console.error("Session fail", error);
      } finally {
        if (mounted) setIsAppInitializing(false);
      }
    };
    restoreSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (!mounted) return;
      setSession(session);
      if (session) fetchProfile(session.user.id).catch(console.error);
      else setUserProfile(null);
      setIsAppInitializing(false);
    });

    return () => { mounted = false; subscription.unsubscribe(); };
  }, []);

  useEffect(() => {
    const mode = searchParams.get('mode');
    setInfinityOpen(mode === 'infinity');
  }, [searchParams]);

  useEffect(() => {
    if (location.state && (location.state as any).returnTo === 'infinity') {
      setInfinityInstantOpen(true);
      if (!searchParams.get('mode')) setSearchParams({ mode: 'infinity' }, { replace: true });
      window.history.replaceState({}, document.title);
    } else {
      setInfinityInstantOpen(false);
    }
  }, [location, searchParams, setSearchParams]);

  useEffect(() => {
    if (location.state && (location.state as any).openPYQ) {
        const state = location.state as any;
        setPyqInitialTab(state.tab || 'objective');
        setInstantOpen(true); 
        setPYQOpen(true);
        window.history.replaceState({}, document.title);
    } else {
        setInstantOpen(false); 
    }
  }, [location]);

  const fetchProfile = async (userId: string) => {
    const data = await api.getProfile(userId);
    if (!data) {
        const { data: { user } } = await supabase.auth.getUser();
        if (user) {
            const fullName = user?.user_metadata?.full_name || 'Student';
            const avatarUrl = user?.user_metadata?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${userId}`;
            const newProfile = await api.createProfile(userId, fullName, avatarUrl);
            if (newProfile) setUserProfile(newProfile);
        }
    } else {
        setUserProfile(data);
    }
  };

  const handleStartTest = async (subject: string, chapterEn: string) => {
    const qs = await api.getQuestionsByChapter(subject, chapterEn);
    if (qs.length > 0) {
      setActiveSubject(subject);
      setActiveTestQuestions(qs);
      navigate('/test');
    } else {
      setComingSoonTitle(`${subject} - ${chapterEn}`);
      navigate('/coming-soon');
    }
  };

  const handleTestComplete = async (stats: any) => {
    setTestStats(stats);
    if (session?.user?.id) {
        const submission: TestSubmission = {
            userId: session.user.id,
            subject: activeSubject || 'Practice',
            testType: 'Practice',
            totalQuestions: stats.correct + stats.wrong + stats.skipped,
            correct: stats.correct,
            wrong: stats.wrong,
            skipped: stats.skipped,
            timeTaken: stats.totalTime,
            date: new Date().toISOString()
        };
        await api.submitTestResult(submission);
        await fetchProfile(session.user.id); 
    }
    navigate('/results', { replace: true });
  };

  const handleInfinitySubjectUpdate = (sub: string | null) => {
      const newParams: any = { mode: 'infinity' };
      if (sub) newParams.subject = sub;
      setSearchParams(newParams, { replace: true });
  };

  if (isAppInitializing) return <SplashScreen />;
  if (!session) return <LoginScreen onLoginSuccess={(s) => { setSession(s); navigate('/', { replace: true }); }} />;

  const NavIcon = ({ icon, label, target }: { icon: string, label: string, target: string }) => {
      const isActive = location.pathname === target || (target !== '/' && location.pathname.startsWith(target));
      return (
        <button onClick={() => navigate(target)} className={`flex flex-col items-center justify-center w-16 gap-0.5 transition-all ${isActive ? 'text-brand-600 dark:text-brand-400' : 'text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300'}`}>
            <i className={`fa-solid ${icon} text-lg mb-0.5`}></i>
            <span className="text-[10px] font-bold tracking-wide leading-none">{label}</span>
            <div className={`w-1 h-1 rounded-full mt-0.5 transition-opacity ${isActive ? 'bg-brand-600 dark:bg-brand-400 opacity-100' : 'opacity-0'}`}></div>
        </button>
      )
  };

  const showNav = ['/', '/practice', '/rewards', '/profile', '/exam'].includes(location.pathname);
  const showTopHeader = location.pathname === '/';

  return (
    <div className="max-w-md mx-auto h-[100dvh] flex flex-col bg-slate-50 dark:bg-slate-950 font-sans relative shadow-2xl overflow-hidden text-slate-900 dark:text-white transition-colors duration-300">

        {showTopHeader && (
            <div className="px-5 pb-3 pt-safe-header bg-white dark:bg-slate-950 flex justify-between items-center sticky top-0 z-30 border-b border-slate-200 dark:border-slate-800 shadow-sm transition-all">
                <div className="flex items-center gap-2"><RaftaarLogo /></div>
                <div className="flex items-center gap-4">
                    {/* Theme Toggle Button */}
                    <button 
                        onClick={toggleTheme}
                        className="w-8 h-8 rounded-full bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 flex items-center justify-center text-slate-500 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-800 transition-colors"
                    >
                        {theme === 'light' ? <Sun size={16} /> : <Moon size={16} />}
                    </button>

                    <div className="flex flex-col items-end">
                        <span className="text-[10px] text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider">Weekly XP</span>
                        <div className="flex items-center gap-1 text-brand-500 dark:text-brand-400 font-black">
                             <i className="fa-solid fa-bolt text-xs"></i>
                             <span>{userProfile?.weekly_xp || 0}</span>
                        </div>
                    </div>
                    <div className="w-9 h-9 rounded-full bg-slate-100 dark:bg-slate-900 p-0.5 border border-slate-200 dark:border-slate-700 cursor-pointer shadow-sm" onClick={() => setDashboardOpen(true)}>
                        <img src={userProfile?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${session.user.email}`} className="w-full h-full rounded-full" alt="User" />
                    </div>
                </div>
            </div>
        )}

        <div className="flex-1 overflow-y-auto hide-scrollbar relative z-10 bg-slate-50 dark:bg-slate-950 transition-colors duration-300">
            <AnimatePresence>
                <Routes location={location} key={location.pathname}>
                    <Route 
                        path="/" 
                        element={
                            <HomeScreen 
                                profile={userProfile} 
                                setComingSoonTitle={(t) => { setComingSoonTitle(t); navigate('/coming-soon'); }} 
                                onOpenInfinity={() => setSearchParams({ mode: 'infinity' }, { replace: true })} 
                                onOpenPYQ={() => { setInstantOpen(false); setPyqInitialTab('objective'); setPYQOpen(true); }}
                                onOpenDashboard={() => setDashboardOpen(true)}
                                onOpenAchievements={() => setAchievementsOpen(true)}
                                navigate={navigate} 
                            />
                        } 
                    />
                    <Route path="/practice" element={<PracticeScreen onSelectChapter={handleStartTest} navigate={navigate} profile={userProfile} />} />
                    <Route path="/exam" element={<ExamScreen showCS={() => { setComingSoonTitle('BSEB Physics Mega Mock'); navigate('/coming-soon'); }} profile={userProfile} navigate={navigate} />} />
                    <Route path="/rewards" element={<RewardsScreen profile={userProfile} session={session} navigate={navigate} />} />

                    <Route 
                        path="/pyq-test" 
                        element={
                            <InfinityTestScreen 
                                userId={session?.user?.id} 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                isPYQ={true} 
                                pyqYear={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => { 
                                    if(session?.user?.id) fetchProfile(session.user.id); 
                                    // Navigate back to Home but with state to re-open PYQ modal at Objective tab
                                    navigate('/', { replace: true, state: { openPYQ: true, tab: 'objective' } });
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/pyq-learn" 
                        element={
                            <PYQSubjectiveScreen 
                                subject={new URLSearchParams(location.search).get('subject') || ''} 
                                year={parseInt(new URLSearchParams(location.search).get('year') || '0')} 
                                onExit={() => navigate('/', { replace: true, state: { openPYQ: true, tab: 'subjective' } })}
                                defaultLanguage={userProfile?.exam_language} 
                            />
                        } 
                    />

                    <Route path="/shorts" element={<ShortsScreen profile={userProfile} session={session} navigate={navigate} onInteractionSubmit={async (qId, isCorrect, isLiked, time) => { if (session?.user?.id) { await api.submitShortsInteraction(session.user.id, qId, isCorrect, isLiked, time); fetchProfile(session.user.id); } }} />} />

                    <Route 
                        path="/results" 
                        element={
                            <ResultScreen 
                                stats={testStats} 
                                onHome={() => {
                                    if (activeSubject) {
                                        navigate(`/practice?subject=${activeSubject}`, { replace: true });
                                    } else {
                                        // For Modal based tests, go home, state will handle re-opening if needed (logic specific to modal types)
                                        navigate('/', { replace: true, state: { openPYQ: true, tab: 'objective' } });
                                    }
                                }} 
                            />
                        } 
                    />

                    <Route 
                        path="/test" 
                        element={
                            <TestInterface 
                                questions={activeTestQuestions} 
                                subjectName={activeSubject} 
                                userId={session?.user?.id} 
                                onExit={() => {
                                    // Fetch Profile on exit to ensure XP updates
                                    if(session?.user?.id) fetchProfile(session.user.id); 

                                    if (activeSubject) {
                                        navigate(`/practice?subject=${encodeURIComponent(activeSubject)}`, { replace: true });
                                    } else {
                                        navigate('/', { replace: true });
                                    }
                                }} 
                                onComplete={handleTestComplete} 
                                onAnswerSubmit={async (qId, opt, correct, timeTaken) => { await api.submitAnswer(session.user.id, qId, opt, correct, timeTaken); }} 
                                defaultLanguage={userProfile?.exam_language}
                            />
                        } 
                    />
                    <Route 
                        path="/infinity-test" 
                        element={
                            infinityConfig ? 
                            <InfinityTestScreen 
                                userId={session.user.id} 
                                subject={infinityConfig.subject} 
                                selectedChapters={infinityConfig.chapters} 
                                onExit={async () => { 
                                    if(session?.user?.id) await fetchProfile(session.user.id); 
                                    // Return to Home with Infinity Modal open logic
                                    const subjectParam = infinityConfig?.subject ? `&subject=${encodeURIComponent(infinityConfig.subject)}` : '';
                                    navigate(`/?mode=infinity${subjectParam}`, { replace: true, state: { returnTo: 'infinity' } });
                                }} 
                                defaultLanguage={userProfile?.exam_language}
                            /> : 
                            <div className="p-10 text-center">Loading...</div>
                        } 
                    />
                    <Route 
                        path="/coming-soon" 
                        element={
                            <FullPageComingSoon 
                                title={comingSoonTitle} 
                                onClose={() => navigate(-1)} 
                                profile={userProfile}
                            />
                        } 
                    />
                </Routes>
            </AnimatePresence>
        </div>

        <InfinityPracticeModal 
            isOpen={isInfinityOpen} 
            onClose={() => setSearchParams({}, { replace: true })} 
            userId={session?.user?.id}
            initialSubject={searchParams.get('subject')}
            onUpdateSubject={handleInfinitySubjectUpdate}
            instantOpen={infinityInstantOpen}
            onStartSession={(subject, chapters) => { 
                setInfinityConfig({ subject, chapters }); 
                navigate('/infinity-test'); 
            }} 
        />

        <PYQDashboard 
            isOpen={isPYQOpen}
            initialTab={pyqInitialTab}
            instantOpen={instantOpen}
            onClose={() => setPYQOpen(false)}
            onSelectYear={async (subject, year, type) => { 
                setPYQOpen(false); 
                if (type === 'objective') { 
                    navigate(`/pyq-test?subject=${subject}&year=${year}`); 
                } else { 
                    navigate(`/pyq-learn?subject=${subject}&year=${year}`); 
                } 
            }} 
        />

        <DashboardModal 
            isOpen={isDashboardOpen} 
            onBack={() => setDashboardOpen(false)} 
            userId={session?.user?.id}
            profile={userProfile}
        />

        <AchievementsModal 
            isOpen={isAchievementsOpen} 
            onBack={() => setAchievementsOpen(false)}
            profile={userProfile}
        />

        <AnimatePresence>
            {exitAttempted && (
                <motion.div 
                    initial={{ y: 50, opacity: 0, scale: 0.9 }}
                    animate={{ y: 0, opacity: 1, scale: 1 }}
                    exit={{ y: 50, opacity: 0, scale: 0.95 }}
                    className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-slate-800 text-white px-6 py-3 rounded-full text-sm font-bold shadow-lg z-[60] border border-slate-700 flex items-center gap-2 pb-safe"
                >
                    <div className="w-2 h-2 bg-brand-400 rounded-full animate-pulse"></div>
                    Press back again to exit
                </motion.div>
            )}
        </AnimatePresence>

        {showNav && (
            <div className="fixed bottom-0 w-full max-w-md bg-white dark:bg-slate-950 border-t border-slate-200 dark:border-slate-800 flex justify-around py-1 pb-safe z-40 shadow-lg transition-colors duration-300">
                <div className="flex w-full justify-around pt-1">
                    <NavIcon icon="fa-house" label="Home" target="/" />
                    <NavIcon icon="fa-book-open" label="Practice" target="/practice" />
                    <NavIcon icon="fa-file-signature" label="Exam" target="/exam" />
                    <NavIcon icon="fa-trophy" label="Rewards" target="/rewards" />
                </div>
            </div>
        )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Crown, Zap, Star, User, ChevronLeft } from 'lucide-react';
import { Profile } from '../types';
import { api } from '../services/api';
import { useBackHandler } from '../hooks/useBackHandler';

interface RewardsScreenProps {
  profile: Profile | null;
  session: any;
  navigate: (path: string | number) => void;
}

export const RewardsScreen: React.FC<RewardsScreenProps> = ({ profile, session, navigate }) => {
    const [leaderboard, setLeaderboard] = useState<Profile[]>([]);
    const [loading, setLoading] = useState(true);

    const totalXP = profile?.total_xp || 0;

    const calculatedLevel = Math.floor(totalXP / 200) + 1;
    const currentLevelStartXP = (calculatedLevel - 1) * 200; 
    const xpProgressInLevel = totalXP - currentLevelStartXP; 
    const progressPercent = Math.min(100, (xpProgressInLevel / 200) * 100);

    const getBadgeFromXP = (xp: number) => {
        if (xp >= 8000) return "Platinum"; 
        if (xp >= 5000) return "Gold";
        if (xp >= 2500) return "Silver";
        if (xp >= 1000) return "Bronze";
        return "Rookie"; 
    };

    useBackHandler(() => {
        navigate('/');
        return true;
    });

    useEffect(() => {
        const fetchLeaderboard = async () => {
            setLoading(true);
            const cacheKey = 'leaderboard_cache';
            const cached = localStorage.getItem(cacheKey);

            // 1. Instant Load from Cache
            if (cached) {
                setLeaderboard(JSON.parse(cached));
                setLoading(false);
            }

            // 2. Background Refresh
            const data = await api.getLeaderboard();
            setLeaderboard(data);
            localStorage.setItem(cacheKey, JSON.stringify(data));
            setLoading(false);
        };
        fetchLeaderboard();
    }, []);

    return (
        <div className="h-[100dvh] flex flex-col bg-slate-950 font-sans text-white">
            {/* Header with Safe Area (pt-safe-header) */}
            <div className="sticky top-0 z-50 px-5 pb-3 pt-safe-header bg-slate-950 flex justify-between items-center border-b border-slate-800 shadow-lg">
                <div className="flex items-center gap-3">
                    <button onClick={() => navigate(-1)} className="text-slate-400 hover:text-white transition-colors p-1 -ml-1 rounded-full active:bg-slate-800">
                        <ChevronLeft size={24} />
                    </button>
                    <h2 className="text-xl font-black text-white tracking-tight">Leaderboard</h2>
                </div>
                <div className="flex items-center gap-3">
                    <div className="flex flex-col items-end mr-1">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Weekly XP</span>
                        <div className="flex items-center gap-1 text-brand-400 font-black leading-none">
                            <Zap size={12} className="fill-brand-400" />
                            <span className="text-sm">{profile?.weekly_xp || 0}</span>
                        </div>
                    </div>
                    <div className="w-9 h-9 rounded-full bg-slate-800 p-0.5 border border-slate-700 shadow-sm">
                        <img src={profile?.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${session?.user?.email || 'user'}`} className="w-full h-full rounded-full" alt="User" />
                    </div>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto hide-scrollbar p-5 pb-safe">
                 {/* Container also needs bottom safe padding via pb-safe in class above or spacer below */}

                 {/* CURRENT LEVEL CARD */}
                 <div className="bg-slate-900 rounded-3xl p-6 shadow-xl border border-slate-800 relative overflow-hidden mb-8 text-center">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-brand-500/10 rounded-full blur-3xl -mr-10 -mt-10 pointer-events-none"></div>

                    <div className="relative z-10 flex flex-col items-center">
                        <div className="relative mb-3">
                            <div className="w-20 h-20 bg-gradient-to-b from-amber-400 to-amber-600 rounded-2xl rotate-45 flex items-center justify-center shadow-lg border-4 border-slate-800">
                                <div className="-rotate-45 flex flex-col items-center">
                                    <span className="text-amber-100 text-[10px] font-bold uppercase tracking-widest">Lvl</span>
                                    <span className="text-white text-3xl font-black">{calculatedLevel}</span>
                                </div>
                            </div>
                        </div>

                        <h3 className="text-lg font-bold text-white mb-2">{getBadgeFromXP(totalXP)}</h3>

                        <div className="bg-slate-800 px-3 py-1.5 rounded-lg border border-slate-700 flex items-center gap-2 mb-5">
                            <Star size={12} className="text-yellow-400 fill-yellow-400" />
                            <span className="text-xs font-bold text-slate-300 uppercase tracking-wide">Total XP: <span className="text-white">{totalXP}</span></span>
                        </div>

                        {/* Progress Bar */}
                        <div className="w-full max-w-[220px]">
                             <div className="flex justify-between text-[10px] font-bold text-slate-500 mb-1.5">
                                <span>{xpProgressInLevel} XP</span>
                                <span>200 XP</span>
                             </div>
                             <div className="h-2 bg-slate-800 rounded-full overflow-hidden border border-slate-700">
                                <div className="h-full bg-gradient-to-r from-brand-500 to-purple-500 rounded-full transition-all duration-1000 ease-out" style={{ width: `${progressPercent}%` }}></div>
                             </div>
                             <p className="text-[10px] text-slate-500 font-bold mt-2">
                                {200 - xpProgressInLevel} XP to Level {calculatedLevel + 1}
                             </p>
                        </div>
                    </div>
                 </div>

                 {/* LEADERBOARD LIST */}
                 <div className="flex items-center gap-2 mb-4 px-1">
                     <Crown size={16} className="text-amber-500 fill-amber-500" />
                     <h3 className="text-slate-400 font-bold text-xs uppercase tracking-widest">Top Students</h3>
                 </div>

                 <div className="space-y-3 pb-24">
                     {loading && leaderboard.length === 0 ? (
                         <div className="text-center py-10 text-slate-600 text-sm">Loading ranks...</div>
                     ) : (
                         leaderboard.map((user, idx) => {
                             const isMe = user.id === profile?.id;
                             const rank = idx + 1;
                             let rankStyle = "bg-slate-800 border-slate-700 text-slate-400";
                             let icon = null;

                             if (rank === 1) {
                                 rankStyle = "bg-yellow-500/10 border-yellow-500/50 text-yellow-500";
                                 icon = <Crown size={14} className="fill-yellow-500 text-yellow-500" />;
                             } else if (rank === 2) {
                                 rankStyle = "bg-slate-700 border-slate-600 text-slate-300";
                             } else if (rank === 3) {
                                 rankStyle = "bg-orange-500/10 border-orange-500/50 text-orange-500";
                             }

                             const dynamicLevel = Math.floor((user.total_xp || 0) / 200) + 1;
                             const dynamicBadge = getBadgeFromXP(user.total_xp || 0);

                             return (
                                 <div key={user.id} className={`relative p-3 rounded-2xl border flex items-center gap-4 transition-transform active:scale-[0.98] ${isMe ? 'bg-brand-900/20 border-brand-500/50 shadow-[0_0_15px_rgba(14,165,233,0.15)]' : 'bg-slate-900 border-slate-800 shadow-sm'}`}>
                                     <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-black text-sm border ${rankStyle}`}>
                                         {icon || rank}
                                     </div>

                                     <div className="w-10 h-10 rounded-full bg-slate-800 p-0.5 shrink-0 border border-slate-700 overflow-hidden flex items-center justify-center">
                                         {user.avatar_url ? (
                                            <img src={user.avatar_url} className="w-full h-full rounded-full object-cover" alt="u" />
                                         ) : (
                                            <User size={20} className="text-slate-500" />
                                         )}
                                     </div>

                                     <div className="flex-1 min-w-0">
                                         <h4 className={`font-bold text-sm truncate ${isMe ? 'text-brand-400' : 'text-white'}`}>
                                             {user.full_name} {isMe && '(You)'}
                                         </h4>
                                         <div className="flex items-center gap-2 mt-0.5">
                                            <span className="text-[9px] font-bold text-slate-900 bg-amber-400 px-1.5 py-0.5 rounded">
                                                Lvl {dynamicLevel}
                                            </span>
                                            <span className="text-[10px] text-slate-500 font-bold uppercase">{dynamicBadge}</span>
                                         </div>
                                     </div>

                                     <div className="text-right">
                                         <span className="block font-black text-white">{user.total_xp}</span>
                                         <span className="text-[9px] font-bold text-slate-500 uppercase">XP</span>
                                     </div>
                                 </div>
                             );
                         })
                     )}
                 </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { Question, Language } from '../types';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, Clock } from 'lucide-react';
import { useBackHandler } from '../hooks/useBackHandler';

interface TestInterfaceProps {
  questions: Question[];
  subjectName?: string;
  userId: string;
  onComplete: (stats: { correct: number, wrong: number, skipped: number, totalTime: number }) => void;
  onExit: () => void;
  onAnswerSubmit: (qId: number, option: string, isCorrect: boolean, timeTaken: number) => void;
  defaultLanguage?: 'Hindi' | 'English'; 
}

export const TestInterface: React.FC<TestInterfaceProps> = ({ 
    questions, 
    subjectName, 
    userId, 
    onComplete, 
    onExit, 
    onAnswerSubmit,
    defaultLanguage = 'English'
}) => {
  const [lang, setLang] = useState<Language>(defaultLanguage === 'Hindi' ? 'hi' : 'en');

  useEffect(() => {
      setLang(defaultLanguage === 'Hindi' ? 'hi' : 'en');
  }, [defaultLanguage]);

  const [currentIndex, setCurrentIndex] = useState(0);
  const [grid, setGrid] = useState<Record<number, { status: string, answer: string | null }>>({});
  const [timer, setTimer] = useState(0); 
  const [showSolution, setShowSolution] = useState(false);
  const [stats, setStats] = useState({ correct: 0, wrong: 0, answered: 0 });
  const [questionStartTime, setQuestionStartTime] = useState<number>(Date.now());
  const [submitting, setSubmitting] = useState(false);

  // Exit Modal State
  const [showExitModal, setShowExitModal] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  // Centralized Logic for Back Action
  const handleNavigationBack = () => {
     if (showExitModal) {
         setShowExitModal(false); // Close Modal if open
         return true; 
     }
     if (!submitting) {
         setShowExitModal(true); // Open Modal
         return true;
     }
     return true; // Trap if submitting
  };

  // Sync Hardware Back Button
  useBackHandler(() => {
    return handleNavigationBack();
  }, !submitting); 

  // Initialize Grid
  useEffect(() => {
    const initialGrid: any = {};
    questions.forEach((_, i) => {
        initialGrid[i] = { status: 'not-visited', answer: null };
    });
    if(initialGrid[0]) initialGrid[0].status = 'not-answered';
    setGrid(initialGrid);
    setQuestionStartTime(Date.now()); 
  }, [questions]);

  // Timer
  useEffect(() => {
    const t = setInterval(() => setTimer(time => time + 1), 1000);
    return () => clearInterval(t);
  }, []);

  const currentQ = questions[currentIndex];
  if (!currentQ) return <div className="p-10 text-center flex flex-col items-center justify-center h-screen bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-white"><div className="w-8 h-8 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div><p className="mt-4 text-slate-500 dark:text-slate-400 font-bold">Loading Test...</p></div>;

  const currentStatus = grid[currentIndex] || { status: 'not-visited', answer: null };

  const handleOptionSelect = (option: string) => {
    if (showSolution) return; 

    // Robust case-insensitive check
    const isCorrect = option.toUpperCase() === (currentQ.correct_option || '').toUpperCase();
    const timeTaken = Math.floor((Date.now() - questionStartTime) / 1000); 

    const newGrid = { ...grid };
    newGrid[currentIndex] = {
        answer: option,
        status: isCorrect ? 'answered' : 'not-answered', 
    };
    setGrid(newGrid);
    setShowSolution(true);

    setStats(s => ({
        ...s,
        answered: s.answered + 1,
        correct: isCorrect ? s.correct + 1 : s.correct,
        wrong: !isCorrect ? s.wrong + 1 : s.wrong
    }));

    onAnswerSubmit(currentQ.id, option, isCorrect, timeTaken);
  };

  const finishTest = async () => {
    if (submitting) return;
    setSubmitting(true);

    let correct = 0, wrong = 0, skipped = 0;
    Object.values(grid).forEach((g: any, i) => {
        const q = questions[i];
        if (g.answer) {
            if (g.answer.toUpperCase() === (q.correct_option || '').toUpperCase()) correct++;
            else wrong++;
        } else {
            skipped++;
        }
    });

    onComplete({ correct, wrong, skipped, totalTime: timer });
  };

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      const nextIndex = currentIndex + 1;
      const newGrid = { ...grid };
      if (newGrid[nextIndex].status === 'not-visited') {
          newGrid[nextIndex].status = 'not-answered';
      }
      setGrid(newGrid);
      setCurrentIndex(nextIndex);
      setQuestionStartTime(Date.now());

      // Lock if next question is already answered
      setShowSolution(!!newGrid[nextIndex]?.answer);

      // Auto Scroll Palette
      if (scrollRef.current) {
          const itemWidth = 40; 
          const containerWidth = scrollRef.current.clientWidth;
          const scrollPos = (nextIndex * itemWidth) - (containerWidth / 2) + (itemWidth / 2);
          scrollRef.current.scrollTo({ left: scrollPos, behavior: 'smooth' });
      }
    } else {
        finishTest();
    }
  };

  const handlePrev = () => {
      if (currentIndex > 0) {
        const prevIndex = currentIndex - 1;
        setCurrentIndex(prevIndex);
        setQuestionStartTime(Date.now());

        // Lock if prev question is already answered
        setShowSolution(!!grid[prevIndex]?.answer);
      }
  }

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const getText = (field: string) => {
    const en = currentQ[`${field}_en` as keyof Question] as string;
    const hi = currentQ[`${field}_hi` as keyof Question] as string;
    return lang === 'hi' ? (hi || en) : en;
  };

  const questionsLeft = questions.length - stats.answered;

  return (
    <div className="flex flex-col h-[100dvh] bg-slate-50 dark:bg-slate-950 relative font-sans animate-fade-in overflow-hidden transition-colors duration-300">

        {/* --- HEADER (Fixed with Safe Area) --- */}
        <div className="px-4 pb-3 pt-safe-header bg-white dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800 flex justify-between items-center z-50 sticky top-0 shadow-sm shrink-0 transition-colors">
             <div className="flex items-center gap-3">
                 {/* UI Back Button */}
                 <button onClick={handleNavigationBack} className="text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white p-1 -ml-1 rounded-full active:bg-slate-100 dark:active:bg-slate-900">
                    <ArrowLeft size={20} />
                 </button>

                 <div className="flex items-center gap-2 bg-slate-100 dark:bg-slate-900 px-2 py-1 rounded-lg border border-slate-200 dark:border-slate-800">
                    <Clock size={14} className="text-slate-500 dark:text-slate-400" />
                    <span className="font-mono font-bold text-slate-700 dark:text-slate-200 text-sm tracking-wider">{formatTime(timer)}</span>
                 </div>
            </div>

            <div className="text-xs text-slate-500 font-bold uppercase tracking-wider truncate max-w-[120px]">{subjectName || 'Test'}</div>

            <button 
                onClick={finishTest} 
                disabled={submitting}
                className="bg-red-500/10 text-red-500 dark:text-red-400 px-3 py-1.5 rounded-lg text-[10px] font-bold border border-red-500/20 hover:bg-red-500/20 transition-colors disabled:opacity-50 flex items-center gap-2"
            >
                {submitting && <div className="w-3 h-3 border-2 border-red-500 border-t-transparent rounded-full animate-spin"></div>}
                {submitting ? 'Saving...' : 'Submit'}
            </button>
        </div>

        {/* --- LIVE STATS GRID --- */}
        <div className="bg-slate-50 dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800 py-2 px-4 flex justify-between items-center text-[10px] font-bold text-slate-500 shrink-0 transition-colors">
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-green-500"></div> {stats.correct} Correct</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div> {stats.wrong} Wrong</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-500"></div> {questionsLeft} Left</div>
        </div>

        {/* --- HORIZONTAL PALETTE STRIP --- */}
        <div className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 py-3 shrink-0 transition-colors">
            <div 
                ref={scrollRef} 
                className="flex overflow-x-auto px-4 gap-2 hide-scrollbar snap-x scroll-smooth"
                style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
            >
                {questions.map((_, i) => {
                    const isCorrect = grid[i]?.answer && grid[i]?.answer?.toUpperCase() === (questions[i].correct_option || '').toUpperCase();
                    let bg = 'bg-slate-100 dark:bg-slate-950 text-slate-500 border-slate-200 dark:border-slate-800';

                    if (grid[i]?.answer) {
                        if (isCorrect) bg = 'bg-green-600 text-white border-green-500';
                        else bg = 'bg-red-600 text-white border-red-500';
                    } else if (i === currentIndex) {
                        bg = 'ring-1 ring-brand-500 border-brand-500 text-brand-600 dark:text-brand-400 bg-brand-50 dark:bg-brand-900/20';
                    }

                    return (
                        <div key={i} onClick={() => { 
                            setCurrentIndex(i); 
                            setShowSolution(!!grid[i]?.answer);
                            setQuestionStartTime(Date.now());
                        }} className={`snap-center shrink-0 w-9 h-9 rounded-lg flex items-center justify-center text-xs font-bold border transition-all cursor-pointer relative ${bg}`}>
                            {i + 1}
                        </div>
                    )
                })}
            </div>
        </div>

        {/* --- QUESTION AREA (Scrollable) --- */}
        <div 
            className="flex-1 overflow-y-auto p-5 pb-32 hide-scrollbar w-full bg-white dark:bg-slate-950 transition-colors"
            style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
        >
            <div className="flex justify-between items-start mb-4">
                 <span className="font-bold text-slate-500 text-[10px] uppercase tracking-wider bg-slate-100 dark:bg-slate-900 px-2 py-1 rounded border border-slate-200 dark:border-slate-800">Question {currentIndex + 1}</span>
                 <button onClick={() => setLang(l => l==='en'?'hi':'en')} className="flex items-center gap-1 bg-slate-100 dark:bg-slate-900 px-3 py-1 rounded-full border border-slate-200 dark:border-slate-800 text-[10px] font-bold text-slate-600 dark:text-slate-400 active:scale-95 transition-transform shadow-sm">
                    <i className="fa-solid fa-language"></i> {lang === 'en' ? 'ENG' : 'HIN'}
                </button>
            </div>

            {/* Question Text with Word Break */}
            <p className="text-lg font-bold text-slate-900 dark:text-white leading-relaxed mb-4 font-serif break-words">
                {getText('question_text')}
            </p>

            <div className="flex items-center gap-2 mb-6">
                <span className="bg-green-500/10 text-green-600 dark:text-green-400 text-[10px] font-bold px-2 py-1 rounded border border-green-500/20">
                    +1.0
                </span>
                <span className="bg-red-500/10 text-red-600 dark:text-red-400 text-[10px] font-bold px-2 py-1 rounded border border-red-500/20">
                    -0.0
                </span>
            </div>

            <div className="space-y-4">
                {['A','B','C','D'].map((opt) => {
                    const optText = getText(`option_${opt.toLowerCase()}`);
                    const isSelected = currentStatus.answer === opt;
                    const isCorrect = opt.toUpperCase() === (currentQ.correct_option || '').toUpperCase();

                    let cardClass = "p-4 rounded-xl border-2 cursor-pointer flex items-start gap-4 transition-all active:scale-[0.98] ";
                    let circleClass = "w-7 h-7 rounded-full border-2 flex items-center justify-center text-sm font-bold shrink-0 transition-colors mt-0.5 ";

                    if (showSolution) {
                        if(isCorrect) {
                            cardClass += "border-green-500 bg-green-50 dark:bg-green-950/30";
                            circleClass += "bg-green-500 text-white border-green-500";
                        } else if (isSelected && !isCorrect) {
                            cardClass += "border-red-500 bg-red-50 dark:bg-red-950/30";
                            circleClass += "bg-red-500 text-white border-red-500";
                        } else {
                            cardClass += "border-slate-200 dark:border-slate-800 opacity-50 bg-slate-50 dark:bg-slate-900/50";
                            circleClass += "border-slate-300 dark:border-slate-700 text-slate-400";
                        }
                    } else {
                        cardClass += "border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-900 hover:border-brand-500/50";
                        circleClass += "border-slate-300 dark:border-slate-700 text-slate-400 bg-white dark:bg-slate-950";
                    }

                    return (
                        <div key={opt} onClick={() => handleOptionSelect(opt)} className={cardClass}>
                            <div className={circleClass}>{opt}</div>
                            <div className="flex-1 text-sm font-medium text-slate-700 dark:text-slate-200 break-words leading-relaxed">
                                {optText}
                            </div>
                        </div>
                    )
                })}
            </div>

            {showSolution && (
                <div className="mt-6 p-5 rounded-xl bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 animate-slide-up">
                    <div className="flex items-center gap-2 mb-2">
                        <i className="fa-solid fa-lightbulb text-blue-500 dark:text-blue-400"></i>
                        <p className="text-xs font-bold text-blue-600 dark:text-blue-400 uppercase">Explanation</p>
                    </div>
                    <p className="text-sm text-slate-700 dark:text-slate-300 leading-relaxed break-words">{getText('solution_short') || "No detailed explanation available for this question."}</p>
                </div>
            )}
        </div>

        {/* --- BOTTOM BAR (Fixed & Safe Area) --- */}
        <div className="absolute bottom-0 w-full bg-white dark:bg-slate-950 border-t border-slate-200 dark:border-slate-800 p-4 pb-safe shadow-[0_-5px_20px_rgba(0,0,0,0.05)] dark:shadow-[0_-5px_20px_rgba(0,0,0,0.2)] z-30 flex items-center gap-4 transition-colors">
            <div className="w-full flex gap-4 pb-2">
                <button onClick={handlePrev} disabled={currentIndex === 0} className="w-1/3 py-3.5 rounded-xl font-bold text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 disabled:opacity-50 hover:bg-slate-200 dark:hover:bg-slate-800 transition-colors">
                    Previous
                </button>

                <button onClick={handleNext} className="flex-1 bg-brand-600 text-white font-bold py-3.5 rounded-xl shadow-lg shadow-brand-500/30 dark:shadow-brand-900 hover:bg-brand-500 transition-colors flex items-center justify-center gap-2 active:scale-[0.98]">
                    {currentIndex === questions.length - 1 ? 'Finish' : 'Save & Next'}
                </button>
            </div>
        </div>

        {/* --- EXIT CONFIRMATION MODAL --- */}
        <AnimatePresence>
          {showExitModal && (
              <>
                <motion.div 
                    initial={{ opacity: 0 }} animate={{ opacity: 0.5 }} exit={{ opacity: 0 }}
                    onClick={() => setShowExitModal(false)}
                    className="fixed inset-0 bg-black z-40"
                />
                <motion.div
                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 25, stiffness: 300 }}
                    className="fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-900 rounded-t-[2rem] z-50 p-6 pb-safe shadow-2xl border-t border-slate-100 dark:border-slate-800"
                >
                    <div className="w-12 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full mx-auto mb-6 mt-2"></div>

                    <div className="flex flex-col items-center text-center mb-8">
                        <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mb-4">
                            <i className="fa-solid fa-arrow-right-from-bracket text-2xl text-red-500"></i>
                        </div>
                        <p className="text-slate-900 dark:text-white font-bold text-lg">Exit Test?</p>
                        <p className="text-slate-500 dark:text-slate-400 text-sm mt-1 max-w-xs leading-relaxed">
                            Your current progress will be lost if you exit without submitting.
                        </p>
                    </div>

                    <div className="flex gap-4 pb-4">
                        <button 
                            onClick={onExit} 
                            className="flex-1 py-3.5 rounded-xl border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 font-bold hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
                        >
                            Exit
                        </button>
                        <button 
                            onClick={() => setShowExitModal(false)} 
                            className="flex-1 py-3.5 rounded-xl bg-brand-600 text-white font-bold shadow-lg shadow-brand-500/30 dark:shadow-brand-900 hover:bg-brand-500 transition-colors"
                        >
                            Continue
                        </button>
                    </div>
                </motion.div>
              </>
          )}
      </AnimatePresence>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Question, Language } from '../types';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowLeft, Clock } from 'lucide-react';
import { useBackHandler } from '../hooks/useBackHandler';

interface TestInterfaceProps {
  questions: Question[];
  subjectName?: string;
  userId: string;
  onComplete: (stats: { correct: number, wrong: number, skipped: number, totalTime: number }) => void;
  onExit: () => void;
  onAnswerSubmit: (qId: number, option: string, isCorrect: boolean, timeTaken: number) => void;
  defaultLanguage?: 'Hindi' | 'English'; 
}

export const TestInterface: React.FC<TestInterfaceProps> = ({ 
    questions, 
    subjectName, 
    userId, 
    onComplete, 
    onExit, 
    onAnswerSubmit,
    defaultLanguage = 'English'
}) => {
  const [lang, setLang] = useState<Language>(defaultLanguage === 'Hindi' ? 'hi' : 'en');

  useEffect(() => {
      setLang(defaultLanguage === 'Hindi' ? 'hi' : 'en');
  }, [defaultLanguage]);

  const [currentIndex, setCurrentIndex] = useState(0);
  const [grid, setGrid] = useState<Record<number, { status: string, answer: string | null }>>({});
  const [timer, setTimer] = useState(0); 
  const [showSolution, setShowSolution] = useState(false);
  const [stats, setStats] = useState({ correct: 0, wrong: 0, answered: 0 });
  const [questionStartTime, setQuestionStartTime] = useState<number>(Date.now());
  const [submitting, setSubmitting] = useState(false);

  // Exit Modal State
  const [showExitModal, setShowExitModal] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  // Centralized Logic for Back Action
  const handleNavigationBack = () => {
     if (showExitModal) {
         setShowExitModal(false); // Close Modal if open
         return true; 
     }
     if (!submitting) {
         setShowExitModal(true); // Open Modal
         return true;
     }
     return true; // Trap if submitting
  };

  // Sync Hardware Back Button
  useBackHandler(() => {
    return handleNavigationBack();
  }, !submitting); 

  // Initialize Grid
  useEffect(() => {
    const initialGrid: any = {};
    questions.forEach((_, i) => {
        initialGrid[i] = { status: 'not-visited', answer: null };
    });
    if(initialGrid[0]) initialGrid[0].status = 'not-answered';
    setGrid(initialGrid);
    setQuestionStartTime(Date.now()); 
  }, [questions]);

  // Timer
  useEffect(() => {
    const t = setInterval(() => setTimer(time => time + 1), 1000);
    return () => clearInterval(t);
  }, []);

  const currentQ = questions[currentIndex];
  if (!currentQ) return <div className="p-10 text-center flex flex-col items-center justify-center h-screen bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-white"><div className="w-8 h-8 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div><p className="mt-4 text-slate-500 dark:text-slate-400 font-bold">Loading Test...</p></div>;

  const currentStatus = grid[currentIndex] || { status: 'not-visited', answer: null };

  const handleOptionSelect = (option: string) => {
    if (showSolution) return; 

    // Robust case-insensitive check
    const isCorrect = option.toUpperCase() === (currentQ.correct_option || '').toUpperCase();
    const timeTaken = Math.floor((Date.now() - questionStartTime) / 1000); 

    const newGrid = { ...grid };
    newGrid[currentIndex] = {
        answer: option,
        status: isCorrect ? 'answered' : 'not-answered', 
    };
    setGrid(newGrid);
    setShowSolution(true);

    setStats(s => ({
        ...s,
        answered: s.answered + 1,
        correct: isCorrect ? s.correct + 1 : s.correct,
        wrong: !isCorrect ? s.wrong + 1 : s.wrong
    }));

    onAnswerSubmit(currentQ.id, option, isCorrect, timeTaken);
  };

  const finishTest = async () => {
    if (submitting) return;
    setSubmitting(true);

    let correct = 0, wrong = 0, skipped = 0;
    Object.values(grid).forEach((g: any, i) => {
        const q = questions[i];
        if (g.answer) {
            if (g.answer.toUpperCase() === (q.correct_option || '').toUpperCase()) correct++;
            else wrong++;
        } else {
            skipped++;
        }
    });

    onComplete({ correct, wrong, skipped, totalTime: timer });
  };

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      const nextIndex = currentIndex + 1;
      const newGrid = { ...grid };
      if (newGrid[nextIndex].status === 'not-visited') {
          newGrid[nextIndex].status = 'not-answered';
      }
      setGrid(newGrid);
      setCurrentIndex(nextIndex);
      setQuestionStartTime(Date.now());

      // Lock if next question is already answered
      setShowSolution(!!newGrid[nextIndex]?.answer);

      // Auto Scroll Palette
      if (scrollRef.current) {
          const itemWidth = 40; 
          const containerWidth = scrollRef.current.clientWidth;
          const scrollPos = (nextIndex * itemWidth) - (containerWidth / 2) + (itemWidth / 2);
          scrollRef.current.scrollTo({ left: scrollPos, behavior: 'smooth' });
      }
    } else {
        finishTest();
    }
  };

  const handlePrev = () => {
      if (currentIndex > 0) {
        const prevIndex = currentIndex - 1;
        setCurrentIndex(prevIndex);
        setQuestionStartTime(Date.now());

        // Lock if prev question is already answered
        setShowSolution(!!grid[prevIndex]?.answer);
      }
  }

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const getText = (field: string) => {
    const en = currentQ[`${field}_en` as keyof Question] as string;
    const hi = currentQ[`${field}_hi` as keyof Question] as string;
    return lang === 'hi' ? (hi || en) : en;
  };

  const questionsLeft = questions.length - stats.answered;

  return (
    <div className="flex flex-col h-[100dvh] bg-slate-50 dark:bg-slate-950 relative font-sans animate-fade-in overflow-hidden transition-colors duration-300">

        {/* --- HEADER (Fixed with Safe Area) --- */}
        <div className="px-4 pb-3 pt-safe-header bg-white dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800 flex justify-between items-center z-50 sticky top-0 shadow-sm shrink-0 transition-colors">
             <div className="flex items-center gap-3">
                 {/* UI Back Button */}
                 <button onClick={handleNavigationBack} className="text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white p-1 -ml-1 rounded-full active:bg-slate-100 dark:active:bg-slate-900">
                    <ArrowLeft size={20} />
                 </button>

                 <div className="flex items-center gap-2 bg-slate-100 dark:bg-slate-900 px-2 py-1 rounded-lg border border-slate-200 dark:border-slate-800">
                    <Clock size={14} className="text-slate-500 dark:text-slate-400" />
                    <span className="font-mono font-bold text-slate-700 dark:text-slate-200 text-sm tracking-wider">{formatTime(timer)}</span>
                 </div>
            </div>

            <div className="text-xs text-slate-500 font-bold uppercase tracking-wider truncate max-w-[120px]">{subjectName || 'Test'}</div>

            <button 
                onClick={finishTest} 
                disabled={submitting}
                className="bg-red-500/10 text-red-500 dark:text-red-400 px-3 py-1.5 rounded-lg text-[10px] font-bold border border-red-500/20 hover:bg-red-500/20 transition-colors disabled:opacity-50 flex items-center gap-2"
            >
                {submitting && <div className="w-3 h-3 border-2 border-red-500 border-t-transparent rounded-full animate-spin"></div>}
                {submitting ? 'Saving...' : 'Submit'}
            </button>
        </div>

        {/* --- LIVE STATS GRID --- */}
        <div className="bg-slate-50 dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800 py-2 px-4 flex justify-between items-center text-[10px] font-bold text-slate-500 shrink-0 transition-colors">
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-green-500"></div> {stats.correct} Correct</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-red-500"></div> {stats.wrong} Wrong</div>
            <div className="flex items-center gap-1.5"><div className="w-2 h-2 rounded-full bg-blue-500"></div> {questionsLeft} Left</div>
        </div>

        {/* --- HORIZONTAL PALETTE STRIP --- */}
        <div className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 py-3 shrink-0 transition-colors">
            <div 
                ref={scrollRef} 
                className="flex overflow-x-auto px-4 gap-2 hide-scrollbar snap-x scroll-smooth"
                style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
            >
                {questions.map((_, i) => {
                    const isCorrect = grid[i]?.answer && grid[i]?.answer?.toUpperCase() === (questions[i].correct_option || '').toUpperCase();
                    let bg = 'bg-slate-100 dark:bg-slate-950 text-slate-500 border-slate-200 dark:border-slate-800';

                    if (grid[i]?.answer) {
                        if (isCorrect) bg = 'bg-green-600 text-white border-green-500';
                        else bg = 'bg-red-600 text-white border-red-500';
                    } else if (i === currentIndex) {
                        bg = 'ring-1 ring-brand-500 border-brand-500 text-brand-600 dark:text-brand-400 bg-brand-50 dark:bg-brand-900/20';
                    }

                    return (
                        <div key={i} onClick={() => { 
                            setCurrentIndex(i); 
                            setShowSolution(!!grid[i]?.answer);
                            setQuestionStartTime(Date.now());
                        }} className={`snap-center shrink-0 w-9 h-9 rounded-lg flex items-center justify-center text-xs font-bold border transition-all cursor-pointer relative ${bg}`}>
                            {i + 1}
                        </div>
                    )
                })}
            </div>
        </div>

        {/* --- QUESTION AREA (Scrollable) --- */}
        <div 
            className="flex-1 overflow-y-auto p-5 pb-32 hide-scrollbar w-full bg-white dark:bg-slate-950 transition-colors"
            style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
        >
            <div className="flex justify-between items-start mb-4">
                 <span className="font-bold text-slate-500 text-[10px] uppercase tracking-wider bg-slate-100 dark:bg-slate-900 px-2 py-1 rounded border border-slate-200 dark:border-slate-800">Question {currentIndex + 1}</span>
                 <button onClick={() => setLang(l => l==='en'?'hi':'en')} className="flex items-center gap-1 bg-slate-100 dark:bg-slate-900 px-3 py-1 rounded-full border border-slate-200 dark:border-slate-800 text-[10px] font-bold text-slate-600 dark:text-slate-400 active:scale-95 transition-transform shadow-sm">
                    <i className="fa-solid fa-language"></i> {lang === 'en' ? 'ENG' : 'HIN'}
                </button>
            </div>

            {/* Question Text with Word Break */}
            <p className="text-lg font-bold text-slate-900 dark:text-white leading-relaxed mb-4 font-sans break-words">
                {getText('question_text')}
            </p>

            <div className="flex items-center gap-2 mb-6">
                <span className="bg-green-500/10 text-green-600 dark:text-green-400 text-[10px] font-bold px-2 py-1 rounded border border-green-500/20">
                    +1.0
                </span>
                <span className="bg-red-500/10 text-red-600 dark:text-red-400 text-[10px] font-bold px-2 py-1 rounded border border-red-500/20">
                    -0.0
                </span>
            </div>

            <div className="space-y-4">
                {['A','B','C','D'].map((opt) => {
                    const optText = getText(`option_${opt.toLowerCase()}`);
                    const isSelected = currentStatus.answer === opt;
                    const isCorrect = opt.toUpperCase() === (currentQ.correct_option || '').toUpperCase();

                    let cardClass = "p-4 rounded-xl border-2 cursor-pointer flex items-start gap-4 transition-all active:scale-[0.98] ";
                    let circleClass = "w-7 h-7 rounded-full border-2 flex items-center justify-center text-sm font-bold shrink-0 transition-colors mt-0.5 ";

                    if (showSolution) {
                        if(isCorrect) {
                            cardClass += "border-green-500 bg-green-50 dark:bg-green-950/30";
                            circleClass += "bg-green-500 text-white border-green-500";
                        } else if (isSelected && !isCorrect) {
                            cardClass += "border-red-500 bg-red-50 dark:bg-red-950/30";
                            circleClass += "bg-red-500 text-white border-red-500";
                        } else {
                            cardClass += "border-slate-200 dark:border-slate-800 opacity-50 bg-slate-50 dark:bg-slate-900/50";
                            circleClass += "border-slate-300 dark:border-slate-700 text-slate-400";
                        }
                    } else {
                        cardClass += "border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-900 hover:border-brand-500/50";
                        circleClass += "border-slate-300 dark:border-slate-700 text-slate-400 bg-white dark:bg-slate-950";
                    }

                    return (
                        <div key={opt} onClick={() => handleOptionSelect(opt)} className={cardClass}>
                            <div className={circleClass}>{opt}</div>
                            <div className="flex-1 text-sm font-medium text-slate-700 dark:text-slate-200 break-words leading-relaxed">
                                {optText}
                            </div>
                        </div>
                    )
                })}
            </div>

            {showSolution && (
                <div className="mt-6 p-5 rounded-xl bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 animate-slide-up">
                    <div className="flex items-center gap-2 mb-2">
                        <i className="fa-solid fa-lightbulb text-blue-500 dark:text-blue-400"></i>
                        <p className="text-xs font-bold text-blue-600 dark:text-blue-400 uppercase">Explanation</p>
                    </div>
                    <p className="text-sm text-slate-700 dark:text-slate-300 leading-relaxed break-words">{getText('solution_short') || "No detailed explanation available for this question."}</p>
                </div>
            )}
        </div>

        {/* --- BOTTOM BAR (Fixed & Safe Area) --- */}
        <div className="absolute bottom-0 w-full bg-white dark:bg-slate-950 border-t border-slate-200 dark:border-slate-800 p-4 pb-safe shadow-[0_-5px_20px_rgba(0,0,0,0.05)] dark:shadow-[0_-5px_20px_rgba(0,0,0,0.2)] z-30 flex items-center gap-4 transition-colors">
            <div className="w-full flex gap-4 pb-2">
                <button onClick={handlePrev} disabled={currentIndex === 0} className="w-1/3 py-3.5 rounded-xl font-bold text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 disabled:opacity-50 hover:bg-slate-200 dark:hover:bg-slate-800 transition-colors">
                    Previous
                </button>

                <button onClick={handleNext} className="flex-1 bg-brand-600 text-white font-bold py-3.5 rounded-xl shadow-lg shadow-brand-500/30 dark:shadow-brand-900 hover:bg-brand-500 transition-colors flex items-center justify-center gap-2 active:scale-[0.98]">
                    {currentIndex === questions.length - 1 ? 'Finish' : 'Save & Next'}
                </button>
            </div>
        </div>

        {/* --- EXIT CONFIRMATION MODAL --- */}
        <AnimatePresence>
          {showExitModal && (
              <>
                <motion.div 
                    initial={{ opacity: 0 }} animate={{ opacity: 0.5 }} exit={{ opacity: 0 }}
                    onClick={() => setShowExitModal(false)}
                    className="fixed inset-0 bg-black z-40"
                />
                <motion.div
                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 25, stiffness: 300 }}
                    className="fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-900 rounded-t-[2rem] z-50 p-6 pb-safe shadow-2xl border-t border-slate-100 dark:border-slate-800"
                >
                    <div className="w-12 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full mx-auto mb-6 mt-2"></div>

                    <div className="flex flex-col items-center text-center mb-8">
                        <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mb-4">
                            <i className="fa-solid fa-arrow-right-from-bracket text-2xl text-red-500"></i>
                        </div>
                        <p className="text-slate-900 dark:text-white font-bold text-lg">Exit Test?</p>
                        <p className="text-slate-500 dark:text-slate-400 text-sm mt-1 max-w-xs leading-relaxed">
                            Your current progress will be lost if you exit without submitting.
                        </p>
                    </div>

                    <div className="flex gap-4 pb-4">
                        <button 
                            onClick={onExit} 
                            className="flex-1 py-3.5 rounded-xl border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 font-bold hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
                        >
                            Exit
                        </button>
                        <button 
                            onClick={() => setShowExitModal(false)} 
                            className="flex-1 py-3.5 rounded-xl bg-brand-600 text-white font-bold shadow-lg shadow-brand-500/30 dark:shadow-brand-900 hover:bg-brand-500 transition-colors"
                        >
                            Continue
                        </button>
                    </div>
                </motion.div>
              </>
          )}
      </AnimatePresence>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Clock, ArrowLeft, AlertTriangle } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Question, Language, TestSubmission } from '../types';
import { api } from '../services/api';
import { useBackHandler } from '../hooks/useBackHandler';

interface InfinityTestScreenProps {
  userId: string;
  selectedChapters?: string[];
  subject: string;
  isPYQ?: boolean;
  pyqYear?: number;
  onExit: () => void;
  defaultLanguage?: 'Hindi' | 'English';
}

const shuffleArray = (array: Question[]) => {
  return array.map(value => ({ value, sort: Math.random() }))
              .sort((a, b) => a.sort - b.sort)
              .map(({ value }) => value);
};

export const InfinityTestScreen: React.FC<InfinityTestScreenProps> = ({ 
    userId, 
    selectedChapters, 
    subject, 
    onExit,
    isPYQ = false,
    pyqYear,
    defaultLanguage = 'English'
}) => {
  const [questions, setQuestions] = useState<Question[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [fetchError, setFetchError] = useState<string | null>(null);

  const [isTestFinished, setIsTestFinished] = useState(false);
  const [showExitModal, setShowExitModal] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [roundCycle, setRoundCycle] = useState<1 | 2 | 3>(1);
  const seenIdsRef = useRef<Set<number>>(new Set()); 
  const hasFetchedNextRound = useRef<boolean>(false);
  const allQuestionsExhausted = useRef<boolean>(false);
  const questionStartTimeRef = useRef<number>(Date.now());
  const scrollRef = useRef<HTMLDivElement>(null);

  const [answers, setAnswers] = useState<Record<number, string>>({}); 
  const [visitedIndices, setVisitedIndices] = useState<Set<number>>(new Set([0]));
  const [elapsedTime, setElapsedTime] = useState(0); 
  const [lang, setLang] = useState<Language>(defaultLanguage === 'Hindi' ? 'hi' : 'en');

  const handleAppBack = () => {
    if (showExitModal) {
      setShowExitModal(false);
      return true;
    }
    if (isTestFinished) {
      onExit();
      return true;
    }
    if (isSubmitting) {
      return true; 
    }
    setShowExitModal(true);
    return true;
  };

  useBackHandler(handleAppBack, true);

  useEffect(() => {
    setLang(defaultLanguage === 'Hindi' ? 'hi' : 'en');
  }, [defaultLanguage]);

  const getQuantityForRound = (cycle: number) => {
      const N = selectedChapters?.length || 1;
      if (cycle === 1) return Math.max(1, N - 1);
      if (cycle === 2) return N;
      return N + 1; 
  };

  useEffect(() => {
    const initData = async () => {
        setLoading(true);
        try {
            if (isPYQ && pyqYear) {
                const data = await api.getPYQs(subject, pyqYear, 'objective');
                if (data.length > 0) {
                    setQuestions(data);
                    allQuestionsExhausted.current = true;
                } else {
                    setFetchError(`No objective questions found for ${subject} ${pyqYear}.`);
                }
            } else if (selectedChapters && selectedChapters.length > 0) {
                const quantity = getQuantityForRound(1);
                const newQuestions = await api.fetchInfinityBatch(selectedChapters, [], quantity);

                if (newQuestions.length > 0) {
                    const randomizedQuestions = shuffleArray(newQuestions);
                    setQuestions(randomizedQuestions);
                    randomizedQuestions.forEach(q => seenIdsRef.current.add(q.id));
                    setRoundCycle(2); 
                } else {
                    setFetchError("No questions found for these chapters.");
                }
            } else {
                setFetchError("Invalid configuration.");
            }
        } catch (err) {
            console.error(err);
            setFetchError("Failed to load questions.");
        } finally {
            setLoading(false);
        }
    };

    initData();
  }, [selectedChapters, userId, isPYQ, subject, pyqYear]);

  useEffect(() => {
    if (isPYQ) return;
    if (loading || loadingMore || isTestFinished || allQuestionsExhausted.current) return;

    if (currentIndex >= questions.length - 3 && !hasFetchedNextRound.current) {
        loadNextRound();
    }
  }, [currentIndex, questions.length, loading, loadingMore, isTestFinished, isPYQ]);

  const loadNextRound = async () => {
      if (!selectedChapters) return;
      hasFetchedNextRound.current = true;
      setLoadingMore(true);
      try {
          const quantity = getQuantityForRound(roundCycle);
          const currentSeenIds = Array.from(seenIdsRef.current) as number[];
          const newBatch = await api.fetchInfinityBatch(selectedChapters, currentSeenIds, quantity);

          if (newBatch.length > 0) {
              const randomizedBatch = shuffleArray(newBatch);
              setQuestions(prev => [...prev, ...randomizedBatch]);
              randomizedBatch.forEach(q => seenIdsRef.current.add(q.id));
              setRoundCycle(prev => (prev === 3 ? 1 : prev + 1) as 1 | 2 | 3);
              hasFetchedNextRound.current = false;
          } else {
              allQuestionsExhausted.current = true;
              hasFetchedNextRound.current = true;
          }
      } catch (err) {
          hasFetchedNextRound.current = false;
      } finally {
          setLoadingMore(false);
      }
  };

  useEffect(() => {
    if (loading || isTestFinished) return;
    const interval = setInterval(() => {
      setElapsedTime(prev => prev + 1);
    }, 1000);
    return () => clearInterval(interval);
  }, [loading, isTestFinished]);

  const handleOptionSelect = (option: string) => {
    const currentQ = questions[currentIndex];
    if (!currentQ || answers[currentQ.id]) return;

    setAnswers(prev => ({ ...prev, [currentQ.id]: option }));

    const timeTaken = Math.floor((Date.now() - questionStartTimeRef.current) / 1000); 
    const isCorrect = option === currentQ.correct_option;

    api.submitAnswer(userId, currentQ.id, option, isCorrect, timeTaken);
  };

  const updateVisited = (index: number) => {
      setVisitedIndices(prev => new Set(prev).add(index));
  };

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      const nextIdx = currentIndex + 1;
      setCurrentIndex(nextIdx);
      updateVisited(nextIdx);
      questionStartTimeRef.current = Date.now();

      if (scrollRef.current) {
          const itemWidth = 44; 
          const containerWidth = scrollRef.current.clientWidth;
          const scrollPos = (nextIdx * itemWidth) - (containerWidth / 2) + (itemWidth / 2);
          scrollRef.current.scrollTo({ left: scrollPos, behavior: 'smooth' });
      }
    } else {
       if (allQuestionsExhausted.current || isPYQ) {
           handleFinishTest();
       } else if (loadingMore) {
           alert("Fetching more questions...");
       }
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      const prevIdx = currentIndex - 1;
      setCurrentIndex(prevIdx);
      updateVisited(prevIdx);
      questionStartTimeRef.current = Date.now();
    }
  };

  const handleFinishTest = async () => {
      if (isSubmitting) return;
      setIsSubmitting(true);

      const totalQ = questions.length;
      const correctCount = questions.filter(q => answers[q.id] === q.correct_option).length;
      const attemptedCount = Object.keys(answers).length;
      const wrongCount = attemptedCount - correctCount;
      const skippedCount = totalQ - attemptedCount;

      const submissionData: TestSubmission = {
          userId: userId,
          subject: subject,
          testType: isPYQ ? 'PYQ' : 'Infinity',
          totalQuestions: totalQ,
          correct: correctCount,
          wrong: wrongCount,
          skipped: skippedCount,
          timeTaken: elapsedTime, 
          date: new Date().toISOString()
      };

      if (userId) {
          await api.submitTestResult(submissionData);
      }

      setIsTestFinished(true);
      setIsSubmitting(false);
  };

  const formatTime = (totalSeconds: number) => {
    const h = Math.floor(totalSeconds / 3600);
    const m = Math.floor((totalSeconds % 3600) / 60);
    const s = totalSeconds % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const getTxt = (en: string | null, hi: string | null) => lang === 'hi' ? (hi || en) : en;

  if (isTestFinished) {
      const totalQuestions = questions.length;
      const attemptedCount = Object.keys(answers).length;
      const correctCount = questions.filter(q => answers[q.id] === q.correct_option).length;
      const wrongCount = attemptedCount - correctCount;
      const visitedCount = visitedIndices.size;
      const notVisitedCount = totalQuestions - visitedCount;
      const notAnsweredCount = visitedCount - attemptedCount; 
      const score = correctCount; 

      return (
          <div className="h-[100dvh] flex flex-col bg-white dark:bg-slate-950 overflow-y-auto font-sans animate-fade-in transition-colors">
              {/* Analytics Header - Safe Area Fixed */}
              <div className="bg-white dark:bg-slate-950 px-5 pb-4 pt-safe-header border-b border-gray-100 dark:border-slate-800 sticky top-0 z-50 flex justify-between items-center shadow-sm">
                  <h2 className="text-lg font-black text-gray-900 dark:text-white">{isPYQ ? `Result - ${pyqYear}` : 'Objective Test'}</h2>
                  <div className="bg-purple-100 dark:bg-purple-900/30 text-purple-700 dark:text-purple-300 px-3 py-1 rounded-full text-xs font-bold font-mono">
                      {formatTime(elapsedTime)}
                  </div>
              </div>

              <div className="p-6 pb-24 space-y-6">
                  <h3 className="text-lg font-bold text-gray-900 dark:text-white">Test Summary</h3>
                  <div className="bg-gray-50 dark:bg-slate-900 rounded-2xl p-5 border border-gray-100 dark:border-slate-800 shadow-sm space-y-4">
                      <div className="bg-white dark:bg-slate-950 p-4 rounded-xl flex justify-between items-center shadow-sm border border-gray-100 dark:border-slate-800">
                          <span className="text-gray-600 dark:text-slate-400 font-medium">Total Questions</span>
                          <span className="text-2xl font-black text-gray-900 dark:text-white">{totalQuestions}</span>
                      </div>
                      <div className="space-y-3">
                          <div className="flex items-center justify-between bg-white dark:bg-slate-950 p-3 rounded-xl border border-gray-100 dark:border-slate-800">
                              <div className="flex items-center gap-3">
                                  <div className="w-3 h-3 rounded-full bg-green-500"></div>
                                  <span className="text-gray-600 dark:text-slate-400 font-medium text-sm">Answered</span>
                              </div>
                              <span className="text-lg font-bold text-gray-900 dark:text-white">{attemptedCount}</span>
                          </div>
                          <div className="flex items-center justify-between bg-white dark:bg-slate-950 p-3 rounded-xl border border-gray-100 dark:border-slate-800">
                              <div className="flex items-center gap-3">
                                  <div className="w-3 h-3 rounded-full bg-red-500"></div>
                                  <span className="text-gray-600 dark:text-slate-400 font-medium text-sm">Not Answered</span>
                              </div>
                              <span className="text-lg font-bold text-gray-900 dark:text-white">{notAnsweredCount}</span>
                          </div>
                      </div>
                  </div>

                  <div className="bg-blue-50 dark:bg-blue-900/20 rounded-2xl p-5 border border-blue-100 dark:border-blue-900/30">
                      <div className="flex justify-between items-center mb-4">
                          <span className="text-blue-800 dark:text-blue-300 font-bold text-sm uppercase tracking-wider">Evaluation</span>
                          <span className="bg-blue-100 dark:bg-blue-900/50 text-blue-700 dark:text-blue-200 px-2 py-1 rounded text-xs font-bold">Marks: +1 / 0</span>
                      </div>
                      <div className="flex gap-4">
                          <div className="flex-1 bg-white dark:bg-slate-950 p-3 rounded-xl flex flex-col items-center justify-center border border-blue-100 dark:border-blue-900/30">
                              <span className="text-2xl font-black text-green-600 dark:text-green-500">{correctCount}</span>
                              <span className="text-[10px] text-gray-400 dark:text-gray-500 font-bold uppercase">Correct</span>
                          </div>
                          <div className="flex-1 bg-white dark:bg-slate-950 p-3 rounded-xl flex flex-col items-center justify-center border border-blue-100 dark:border-blue-900/30">
                              <span className="text-2xl font-black text-red-500 dark:text-red-400">{wrongCount}</span>
                              <span className="text-[10px] text-gray-400 dark:text-gray-500 font-bold uppercase">Wrong</span>
                          </div>
                          <div className="flex-1 bg-white dark:bg-slate-950 p-3 rounded-xl flex flex-col items-center justify-center border border-blue-100 dark:border-blue-900/30">
                              <span className="text-2xl font-black text-blue-600 dark:text-blue-400">{score}</span>
                              <span className="text-[10px] text-gray-400 dark:text-gray-500 font-bold uppercase">Score</span>
                          </div>
                      </div>
                  </div>
              </div>

              <div className="fixed bottom-0 w-full bg-white dark:bg-slate-950 border-t border-gray-100 dark:border-slate-800 p-4 pb-safe z-30 shadow-[0_-5px_20px_rgba(0,0,0,0.05)] dark:shadow-[0_-5px_20px_rgba(0,0,0,0.2)]">
                  <button onClick={onExit} className="w-full py-4 bg-brand-600 text-white font-bold rounded-xl shadow-lg hover:scale-[1.01] transition-transform">
                      Return to Dashboard
                  </button>
              </div>
          </div>
      )
  }

  if (loading) {
      return (
          <div className="h-screen flex items-center justify-center bg-white dark:bg-slate-950 flex-col gap-4">
              <div className="w-10 h-10 border-4 border-brand-600 border-t-transparent rounded-full animate-spin"></div>
              <p className="text-gray-500 dark:text-slate-400 font-medium text-sm animate-pulse">Preparing Session...</p>
          </div>
      );
  }

  if (fetchError) {
      return (
          <div className="h-screen flex flex-col items-center justify-center bg-white dark:bg-slate-950 gap-6 p-6 text-center">
              <p className="text-red-500 dark:text-red-400 font-medium">{fetchError}</p>
              <button onClick={onExit} className="px-6 py-2 bg-gray-100 dark:bg-slate-800 rounded-lg text-sm font-bold text-slate-700 dark:text-slate-300">Back</button>
          </div>
      )
  }

  const currentQ = questions[currentIndex];
  if (!currentQ) return null;

  const currentAnswer = answers[currentQ.id];

  return (
    <div className="flex flex-col h-[100dvh] bg-white dark:bg-slate-950 relative font-sans text-gray-900 dark:text-white overflow-hidden transition-colors">

      {/* 1. Header - Fixed Safe Area */}
      <div className="px-4 pb-2 pt-safe-header bg-white dark:bg-slate-950 flex justify-between items-center shrink-0 shadow-sm border-b border-gray-100 dark:border-slate-800 z-10 sticky top-0 transition-colors">
          <div className="flex items-center gap-3">
              <button onClick={handleAppBack} className="p-2 -ml-2 text-gray-500 dark:text-slate-400 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-full">
                  <ArrowLeft size={20} />
              </button>
              <div className="flex flex-col">
                  <span className="text-[10px] font-bold text-gray-400 dark:text-slate-500 uppercase tracking-wider">{subject} {isPYQ && `• ${pyqYear}`}</span>
                  <div className="flex items-center gap-1.5 text-gray-800 dark:text-white font-medium leading-none">
                      <Clock size={14} className="text-brand-600 dark:text-brand-400" />
                      <span className="font-mono text-sm">{formatTime(elapsedTime)}</span>
                  </div>
              </div>
          </div>

          <button onClick={handleFinishTest} disabled={isSubmitting} className="text-white text-xs font-bold bg-brand-600 px-5 py-2 rounded-lg shadow-md shadow-brand-200 dark:shadow-brand-900 hover:bg-brand-700 transition-colors disabled:opacity-70">
              {isSubmitting ? 'Saving...' : 'Submit'}
          </button>
      </div>

      {/* 2. Top Palette - Below Header */}
      <div className="bg-gray-50/50 dark:bg-slate-900 border-b border-gray-100 dark:border-slate-800 py-2 shrink-0 flex items-center gap-2 px-3 transition-colors">
          <div ref={scrollRef} className="flex-1 overflow-x-auto hide-scrollbar flex items-center gap-2.5 scroll-smooth">
              {questions.map((q, i) => {
                  const isActive = i === currentIndex;
                  const ans = answers[q.id];
                  const isCorrect = ans && ans === q.correct_option;

                  let styleClass = "bg-white dark:bg-slate-950 border-gray-200 dark:border-slate-700 text-gray-500 dark:text-slate-400"; 

                  if (ans) {
                      styleClass = isCorrect 
                        ? "bg-green-100 dark:bg-green-900/30 border-green-500 text-green-700 dark:text-green-400" 
                        : "bg-blue-100 dark:bg-blue-900/30 border-blue-500 text-blue-700 dark:text-blue-400";
                  } else if (isActive) {
                      styleClass = "border-brand-600 text-brand-600 dark:text-brand-400 ring-1 ring-brand-100 dark:ring-brand-900/50";
                  }

                  return (
                    <button 
                        key={i} 
                        onClick={() => { setCurrentIndex(i); updateVisited(i); }}
                        className={`w-9 h-9 shrink-0 rounded-lg flex items-center justify-center text-sm font-bold border transition-all ${styleClass}`}
                    >
                        {i + 1}
                    </button>
                  )
              })}
              {loadingMore && <div className="w-4 h-4 border-2 border-brand-600 border-t-transparent rounded-full animate-spin shrink-0"></div>}
          </div>
          <div className="h-6 w-[1px] bg-gray-200 dark:bg-slate-800 mx-1"></div>
          <div className="text-[10px] font-bold text-gray-400 dark:text-slate-500">{currentIndex + 1}/{questions.length}</div>
      </div>

      {/* 3. Question Area - Scrollable */}
      <div className="flex-1 overflow-y-auto p-5 pb-32 bg-white dark:bg-slate-950 w-full transition-colors">

          <div className="flex justify-between items-start mb-4">
              <span className="font-bold text-gray-400 dark:text-slate-500 text-[10px] uppercase tracking-wider bg-gray-100 dark:bg-slate-900 px-2 py-1 rounded">Question {currentIndex + 1}</span>
              <button onClick={() => setLang(l => l==='en'?'hi':'en')} className="flex items-center gap-1 bg-brand-50 dark:bg-brand-900/20 px-3 py-1 rounded-full border border-brand-100 dark:border-brand-900/50 text-[10px] font-bold text-brand-700 dark:text-brand-400">
                  {lang === 'en' ? 'ENG' : 'HIN'}
              </button>
          </div>

          {/* Question Text - Break Words for Mobile */}
          <div className="mb-4">
              <p className="text-lg font-bold text-gray-900 dark:text-white leading-relaxed font-sans break-words">
                  {getTxt(currentQ.question_text_en, currentQ.question_text_hi)}
              </p>
          </div>

          <div className="flex items-center gap-2 mb-6">
              <span className="px-2 py-0.5 rounded bg-gray-100 dark:bg-slate-900 text-[9px] font-bold text-gray-500 dark:text-slate-400 border border-gray-200 dark:border-slate-800 w-fit">
                  +1.0 Marks
              </span>
              {currentQ.exam_year && (
                  <span className="px-2 py-0.5 rounded bg-amber-50 dark:bg-amber-900/20 text-[9px] font-bold text-amber-700 dark:text-amber-400 border border-amber-100 dark:border-amber-900/50 w-fit flex items-center gap-1">
                      <span className="w-1.5 h-1.5 rounded-full bg-amber-500"></span> {currentQ.exam_year}
                  </span>
              )}
          </div>

          {/* Options */}
          <div className="space-y-4">
              {['A', 'B', 'C', 'D'].map((opt) => {
                  const optionText = getTxt(
                      currentQ[`option_${opt.toLowerCase()}_en` as keyof Question] as string,
                      currentQ[`option_${opt.toLowerCase()}_hi` as keyof Question] as string
                  );

                  const isSelected = currentAnswer === opt;
                  const isCorrectAnswer = currentQ.correct_option === opt;

                  let cardClass = "bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-800 text-gray-600 dark:text-slate-300 hover:border-gray-300 dark:hover:border-slate-700";
                  let circleClass = "bg-gray-100 dark:bg-slate-800 text-gray-500 dark:text-slate-400 border-gray-200 dark:border-slate-700";

                  if (currentAnswer) {
                      if (isCorrectAnswer) {
                          cardClass = "bg-green-50 dark:bg-green-900/30 border-green-500 text-green-800 dark:text-green-300";
                          circleClass = "bg-green-500 text-white border-green-500";
                      } else if (isSelected && !isCorrectAnswer) {
                          cardClass = "bg-blue-50 dark:bg-blue-900/30 border-blue-500 text-blue-800 dark:text-blue-300";
                          circleClass = "bg-blue-500 text-white border-blue-500";
                      } else {
                          cardClass = "opacity-50 border-gray-100 dark:border-slate-800";
                      }
                  }

                  return (
                      <div 
                        key={opt} 
                        onClick={() => handleOptionSelect(opt)}
                        className={`p-4 rounded-xl border-2 flex items-start gap-4 cursor-pointer transition-all active:scale-[0.98] ${cardClass}`}
                      >
                          <div className={`w-6 h-6 rounded-full border flex items-center justify-center text-xs font-bold shrink-0 mt-0.5 transition-colors ${circleClass}`}>
                              {opt}
                          </div>
                          <div className="text-sm font-medium leading-snug break-words flex-1">
                              {optionText}
                          </div>
                      </div>
                  )
              })}
          </div>

      </div>

      {/* 4. Footer Buttons - Fixed Safe Area */}
      <div className="absolute bottom-0 w-full bg-white dark:bg-slate-950 border-t border-gray-100 dark:border-slate-800 p-4 pb-safe z-20 flex items-center justify-between gap-4 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] dark:shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.2)] transition-colors">
          <div className="w-full flex gap-4 pb-2">
            <button 
                onClick={handlePrev} 
                disabled={currentIndex === 0}
                className="px-6 py-3 rounded-xl font-bold text-brand-600 dark:text-brand-400 bg-white dark:bg-slate-900 border-2 border-brand-600 dark:border-brand-500 disabled:opacity-50 disabled:border-gray-200 dark:disabled:border-slate-800 disabled:text-gray-400 dark:disabled:text-slate-600 transition-colors w-1/3 text-sm"
            >
                Prev
            </button>

            <button 
                onClick={handleNext}
                className="px-6 py-3 rounded-xl font-bold text-white bg-brand-600 shadow-lg shadow-brand-200 dark:shadow-brand-900 hover:bg-brand-700 transition-transform active:scale-95 w-2/3 text-sm"
            >
                {currentIndex === questions.length - 1 && (allQuestionsExhausted.current || isPYQ) ? 'Finish' : 'Next'}
            </button>
          </div>
      </div>

      {/* --- EXIT MODAL --- */}
      <AnimatePresence>
          {showExitModal && (
              <>
                <motion.div 
                    initial={{ opacity: 0 }} animate={{ opacity: 0.5 }} exit={{ opacity: 0 }}
                    onClick={() => setShowExitModal(false)}
                    className="fixed inset-0 bg-black z-40"
                />
                <motion.div
                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 25, stiffness: 300 }}
                    className="fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-900 rounded-t-[2rem] z-50 p-6 pb-safe shadow-2xl border-t border-slate-100 dark:border-slate-800"
                >
                    <div className="w-12 h-1 bg-gray-200 dark:bg-slate-700 rounded-full mx-auto mb-6 mt-2"></div>

                    <div className="flex flex-col items-center text-center mb-8">
                        <div className="w-16 h-16 bg-red-50 dark:bg-red-900/30 rounded-full flex items-center justify-center mb-4">
                            <AlertTriangle className="text-red-500 dark:text-red-400" size={32} />
                        </div>
                        <p className="text-gray-800 dark:text-white font-bold text-lg">Exit Test?</p>
                        <p className="text-gray-500 dark:text-slate-400 text-sm mt-1 max-w-xs leading-relaxed">
                            Your progress will be saved, but the test session will end.
                        </p>
                    </div>

                    <div className="flex gap-4 pb-4">
                        <button 
                            onClick={onExit} 
                            className="flex-1 py-3.5 rounded-xl border border-gray-200 dark:border-slate-700 text-gray-700 dark:text-slate-300 font-bold hover:bg-gray-50 dark:hover:bg-slate-800 transition-colors"
                        >
                            Exit
                        </button>
                        <button 
                            onClick={() => setShowExitModal(false)} 
                            className="flex-1 py-3.5 rounded-xl bg-brand-600 text-white font-bold shadow-lg shadow-brand-200 dark:shadow-brand-900 hover:bg-brand-700 transition-colors"
                        >
                            Resume
                        </button>
                    </div>
                </motion.div>
              </>
          )}
      </AnimatePresence>

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ArrowLeft, ZoomIn, ZoomOut, CheckCircle } from 'lucide-react';
import { PYQQuestion, Language } from '../types';
import { api } from '../services/api';
import { useBackHandler } from '../hooks/useBackHandler';

interface PYQSubjectiveScreenProps {
  subject: string;
  year: number;
  onExit: () => void;
  defaultLanguage?: 'Hindi' | 'English';
}

export const PYQSubjectiveScreen: React.FC<PYQSubjectiveScreenProps> = ({ 
    subject, 
    year, 
    onExit,
    defaultLanguage = 'English' 
}) => {
  const [questions, setQuestions] = useState<PYQQuestion[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [lang, setLang] = useState<Language>(defaultLanguage === 'Hindi' ? 'hi' : 'en');
  const [fontSize, setFontSize] = useState(16);

  useEffect(() => {
      setLang(defaultLanguage === 'Hindi' ? 'hi' : 'en');
  }, [defaultLanguage]);

  const handleAppBack = () => {
    onExit(); 
    return true;
  };

  useBackHandler(handleAppBack);

  useEffect(() => {
    const fetchQuestions = async () => {
        setLoading(true);
        const data = await api.getPYQs(subject, year, 'subjective');
        setQuestions(data);
        setLoading(false);
    };
    if (subject && year) {
        fetchQuestions();
    }
  }, [subject, year]);

  const currentQ = questions[currentIndex];

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      onExit();
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
    }
  };

  const getTxt = (en?: string | null, hi?: string | null) => lang === 'hi' ? (hi || en) : en;

  if (loading) {
      return (
        <div className="h-full flex flex-col items-center justify-center bg-white dark:bg-slate-950 gap-4 transition-colors">
            <div className="w-10 h-10 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-slate-500 dark:text-slate-400 font-medium text-sm animate-pulse">Loading Questions...</p>
        </div>
      );
  }

  if (!questions || questions.length === 0) {
    return (
      <div className="h-full flex flex-col items-center justify-center bg-white dark:bg-slate-950 transition-colors">
        <p className="text-slate-500 dark:text-slate-400 font-medium">No subjective questions found for this year.</p>
        <button onClick={handleAppBack} className="mt-4 px-6 py-2 bg-slate-100 dark:bg-slate-800 rounded-lg text-sm font-bold text-slate-700 dark:text-white hover:bg-slate-200 dark:hover:bg-slate-700">Go Back</button>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] flex flex-col bg-white dark:bg-slate-950 font-sans animate-fade-in text-slate-900 dark:text-white transition-colors duration-300">

      {/* 1. Header (Safe Area pt-safe-header) */}
      <div className="px-4 pb-3 pt-safe-header bg-white dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800 flex justify-between items-center sticky top-0 z-50 shadow-sm transition-colors">
        <div className="flex items-center gap-3">
          <button onClick={handleAppBack} className="p-2 -ml-2 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
            <ArrowLeft size={22} />
          </button>
          <div>
            <h2 className="text-lg font-black text-slate-900 dark:text-white leading-none">Learn Subjective</h2>
            <p className="text-[10px] font-bold text-slate-500 dark:text-slate-500 uppercase mt-1">{subject} • {year}</p>
          </div>
        </div>

        <div className="flex items-center bg-slate-100 dark:bg-slate-900 rounded-lg border border-slate-200 dark:border-slate-800 p-1">
          <button 
            onClick={() => setFontSize(s => Math.max(12, s - 2))}
            className="p-1.5 text-slate-400 hover:text-brand-500 active:bg-slate-200 dark:active:bg-slate-800 rounded-md transition-all"
          >
            <ZoomOut size={16} />
          </button>
          <div className="w-[1px] h-4 bg-slate-200 dark:bg-slate-800 mx-1"></div>
          <button 
            onClick={() => setFontSize(s => Math.min(24, s + 2))}
            className="p-1.5 text-slate-400 hover:text-brand-500 active:bg-slate-200 dark:active:bg-slate-800 rounded-md transition-all"
          >
            <ZoomIn size={16} />
          </button>
        </div>
      </div>

      {/* 2. Top Bar */}
      <div className="px-5 py-3 flex justify-between items-center bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 transition-colors">
        <div className="flex gap-1 overflow-x-auto hide-scrollbar max-w-[200px]">
            {questions.map((_, idx) => (
                <div 
                    key={idx} 
                    className={`h-1.5 rounded-full transition-all duration-300 shrink-0 ${idx === currentIndex ? 'w-6 bg-brand-500' : 'w-1.5 bg-slate-300 dark:bg-slate-700'}`}
                />
            ))}
        </div>
        <button onClick={() => setLang(l => l==='en'?'hi':'en')} className="flex items-center gap-1 bg-slate-100 dark:bg-slate-800 px-3 py-1 rounded-full border border-slate-200 dark:border-slate-700 text-[10px] font-bold text-slate-600 dark:text-slate-300 shadow-sm shrink-0 hover:bg-slate-200 dark:hover:bg-slate-700">
            {lang === 'en' ? 'ENG' : 'HIN'}
        </button>
      </div>

      {/* 3. Content Area */}
      <div className="flex-1 overflow-y-auto p-6 pb-32 w-full bg-white dark:bg-slate-950 transition-colors">

        <div className="mb-8">
            <div className="flex items-center justify-between mb-3">
                <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Question {currentIndex + 1}</span>
                {currentQ.marks && (
                    <span className="bg-brand-50 dark:bg-brand-900/30 text-brand-600 dark:text-brand-400 px-2 py-1 rounded text-[10px] font-bold border border-brand-200 dark:border-brand-900/50">
                        +{currentQ.marks} Marks
                    </span>
                )}
            </div>
            <h1 
                className="font-bold text-slate-900 dark:text-white leading-snug font-sans break-words"
                style={{ fontSize: `${fontSize + 4}px` }}
            >
                {getTxt(currentQ.question_text_en, currentQ.question_text_hi)}
            </h1>
        </div>

        <div className="relative pl-4 border-l-2 border-green-500">
            <div className="absolute -left-[9px] -top-1 w-4 h-4 bg-green-500 rounded-full flex items-center justify-center text-white ring-4 ring-white dark:ring-slate-950">
                <CheckCircle size={10} strokeWidth={3} />
            </div>
            <h3 className="text-green-600 dark:text-green-400 font-bold text-sm uppercase mb-3 ml-2">Solution</h3>
            <div 
                className="text-slate-700 dark:text-slate-300 leading-relaxed ml-2 font-sans break-words"
                style={{ fontSize: `${fontSize}px` }}
            >
                {getTxt(currentQ.answer_text_en, currentQ.answer_text_hi) || getTxt(currentQ.solution_short_en, currentQ.solution_short_hi) || "Detailed answer not available."}
            </div>
        </div>

      </div>

      {/* 4. Bottom Navigation - Fixed Safe Area */}
      <div className="fixed bottom-0 w-full bg-white dark:bg-slate-950 border-t border-slate-200 dark:border-slate-800 p-4 pb-safe z-30 shadow-[0_-5px_20px_rgba(0,0,0,0.05)] dark:shadow-[0_-5px_20px_rgba(0,0,0,0.2)] flex gap-4 transition-colors">
        <button 
            onClick={handlePrev}
            disabled={currentIndex === 0}
            className="flex-1 py-3.5 rounded-xl font-bold text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-colors hover:bg-slate-200 dark:hover:bg-slate-800"
        >
            Previous
        </button>
        <button 
            onClick={handleNext}
            className="flex-1 py-3.5 rounded-xl font-bold text-white bg-brand-600 shadow-lg shadow-brand-500/30 dark:shadow-brand-900 hover:bg-brand-500 transition-transform active:scale-[0.98]"
        >
            {currentIndex === questions.length - 1 ? 'Finish' : 'Next'}
        </button>
      </div>

    </div>
  );
};

import { supabase } from './supabase';
import { Question, Profile, PYQQuestion, DashboardStats, TestHistoryItem, TestSubmission } from '../types';
import { updateUserXP } from './xpService'; 

const FALLBACK_SUBJECTS = ['Physics', 'Chemistry', 'Maths', 'Biology', 'Hindi', 'English'];
const FALLBACK_QUESTIONS: Question[] = [
  {
    id: 101, subject: 'Physics', chapter_name_en: 'Electric Charges and Fields', chapter_name_hi: 'वैद्युत आवेश तथा क्षेत्र', question_text_en: 'The SI unit of electric flux is:', question_text_hi: 'विद्युत फ्लक्स का SI मात्रक है:', option_a_en: 'Weber', option_a_hi: 'वेबर', option_b_en: 'Nm²C⁻¹', option_b_hi: 'Nm²C⁻¹', option_c_en: 'Newton', option_c_hi: 'न्यूटन', option_d_en: 'Volt', option_d_hi: 'वोल्ट', correct_option: 'B', solution_short_en: 'Electric flux Φ = E.dA = (N/C) * m² = Nm²C⁻¹.', solution_short_hi: 'विद्युत फ्लक्स Φ = E.dA = (N/C) * m² = Nm²C⁻¹.', exam_year: '2021A'
  }
];

export const api = {
  // --- AUTHENTICATION ---

  registerOrLogin: async (data: { fullName: string; mobileNumber: string; location: string; examLanguage: 'Hindi' | 'English' }) => {
    try {
        const email = `${data.mobileNumber}@raftaar.local`; 
        const password = `${data.mobileNumber}raftaar2026`; 

        // Try Signing In
        const { data: signInData, error: signInError } = await supabase.auth.signInWithPassword({
            email,
            password
        });

        if (signInData.user) {
            // Update existing profile
            await supabase.from('profiles').update({
                full_name: data.fullName,
                location: data.location,
                mobile_number: data.mobileNumber,
                exam_language: data.examLanguage,
                last_active_at: new Date().toISOString()
            }).eq('id', signInData.user.id);

            return { user: signInData.user, session: signInData.session, error: null };
        }

        // Create New User
        const { data: signUpData, error: signUpError } = await supabase.auth.signUp({
            email,
            password,
            options: { data: { full_name: data.fullName } }
        });

        if (signUpError) throw signUpError;
        if (!signUpData.user) throw new Error("User creation failed");

        // Insert Profile - Default to Bronze and Level 1
        const profileData = {
            id: signUpData.user.id,
            full_name: data.fullName,
            mobile_number: data.mobileNumber,
            location: data.location,
            exam_language: data.examLanguage,
            avatar_url: `https://api.dicebear.com/7.x/avataaars/svg?seed=${data.fullName}`,
            study_minutes: 0,
            total_xp: 0,
            weekly_xp: 0,
            current_level: 1, // Start at Level 1
            current_badge: 'Bronze', // Start as Bronze
            last_active_at: new Date().toISOString(),
        };

        const { error: profileError } = await supabase.from('profiles').upsert(profileData);
        if (profileError) throw profileError;

        return { user: signUpData.user, session: signUpData.session, error: null };

    } catch (error: any) {
        return { user: null, session: null, error: error };
    }
  },

  getProfile: async (userId: string): Promise<Profile | null> => {
    try {
      const { data, error } = await supabase
        .from('leaderboard_view')
        .select('*')
        .eq('id', userId)
        .single();

      if (!error && data) return data;

      const { data: basicData, error: basicError } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      if (basicError) return null;
      return { ...basicData, global_rank: 0 }; 
    } catch (e) { return null; }
  },

  createProfile: async (userId: string, fullName: string, avatarUrl: string): Promise<Profile | null> => {
    try {
        const newProfile = {
            id: userId,
            full_name: fullName,
            avatar_url: avatarUrl,
            study_minutes: 0,
            total_xp: 0,
            weekly_xp: 0,
            current_level: 1,
            current_badge: 'Bronze',
            last_active_at: new Date().toISOString(),
        };

        const { data, error } = await supabase
            .from('profiles')
            .upsert(newProfile, { onConflict: 'id' })
            .select()
            .single();

        if (error) return null;
        return data;
    } catch (e) { return null; }
  },

  getSubjects: async (): Promise<string[]> => {
    try {
      const { data, error } = await supabase.from('questions').select('subject');
      if (error || !data || data.length === 0) return FALLBACK_SUBJECTS;
      const subjects: string[] = Array.from(new Set((data as any[]).map((d: any) => String(d.subject))));
      return subjects.length > 0 ? subjects : FALLBACK_SUBJECTS;
    } catch (e) { return FALLBACK_SUBJECTS; }
  },

  getChapters: async (subject: string): Promise<{en: string, hi: string}[]> => {
    try {
      const { data, error } = await supabase.from('questions').select('chapter_name_en, chapter_name_hi').eq('subject', subject);
      if (error || !data) return [];
      const uniqueMap = new Map();
      data.forEach((item: any) => {
        if (!uniqueMap.has(item.chapter_name_en)) uniqueMap.set(item.chapter_name_en, { en: item.chapter_name_en, hi: item.chapter_name_hi });
      });
      return Array.from(uniqueMap.values());
    } catch (e) { return []; }
  },

  getQuestionsByChapter: async (subject: string, chapterEn: string): Promise<Question[]> => {
    try {
      const { data } = await supabase.from('questions').select('*').eq('subject', subject).eq('chapter_name_en', chapterEn);
      return data && data.length > 0 ? data : FALLBACK_QUESTIONS.filter(q => q.subject === subject);
    } catch (e) { return []; }
  },

  getRandomQuestion: async (): Promise<Question | null> => {
    try {
       const { data } = await supabase.from('questions').select('*').limit(20); 
       if(!data || data.length === 0) return FALLBACK_QUESTIONS[0];
       return data[Math.floor(Math.random() * data.length)];
    } catch(e) { return FALLBACK_QUESTIONS[0]; }
  },

  submitAnswer: async (userId: string, questionId: number, selectedOption: string, isCorrect: boolean, timeTaken: number) => {
    if (userId === 'demo-user') return true; 

    // Attempt to log the interaction inside a try-catch so it doesn't block XP update
    try {
      await supabase.from('user_interactions').insert({
          user_id: userId, question_id: questionId, is_correct: isCorrect, time_spent_seconds: timeTaken
      });
    } catch (err) {
      console.log("Interaction logging skipped (duplicate or error)", err);
    }

    // Always update XP if correct, regardless of interaction log success
    if (isCorrect) {
        await updateUserXP(userId, 1);
    }
    return true;
  },

  submitTestResult: async (data: TestSubmission) => {
    if (data.userId === 'demo-user') return { success: true };
    try {
        const { error } = await supabase.from('user_test_sessions').insert({
            user_id: data.userId, test_type: data.testType, subject: data.subject, total_questions: data.totalQuestions,
            correct_count: data.correct, wrong_count: data.wrong, skipped_count: data.skipped, time_taken_seconds: data.timeTaken, created_at: data.date
        });
        return { success: !error, error };
    } catch (e) { return { success: false }; }
  },

  submitShortsInteraction: async (userId: string, questionId: number, isCorrect: boolean, isLiked: boolean, timeSpentSeconds: number) => {
    if (userId === 'demo-user') return true;

    try {
      await supabase.from('user_interactions').insert({
          user_id: userId, question_id: questionId, is_correct: isCorrect, is_liked: isLiked, time_spent_seconds: timeSpentSeconds
      });
    } catch (err) {
       // Ignore duplicate logs
    }

    if (isCorrect) {
        await updateUserXP(userId, 1);
    }
    return true;
  },

  getLeaderboard: async (): Promise<Profile[]> => {
      try {
          const { data, error } = await supabase
            .from('leaderboard_view')
            .select('*')
            .order('total_xp', { ascending: false })
            .limit(50);

          if (error) throw error;
          return data as Profile[];
      } catch (e) { return []; }
  },

  getDashboardData: async (userId: string): Promise<DashboardStats> => {
    if (userId === 'demo-user') return { totalQuestions: 0, totalCorrect: 0, totalWrong: 0, accuracy: 0, dailyAttempts: 0, dailyCorrect: 0, dailyWrong: 0, dailyAvgTime: 0, totalTests: 0, history: [], graphData: [] };

    try {
        const { data: sessions } = await supabase.from('user_test_sessions').select('*').eq('user_id', userId).order('created_at', { ascending: false });
        if (!sessions) return { totalQuestions: 0, totalCorrect: 0, totalWrong: 0, accuracy: 0, dailyAttempts: 0, dailyCorrect: 0, dailyWrong: 0, dailyAvgTime: 0, totalTests: 0, history: [], graphData: [] };

        let totalQuestions = 0, totalCorrect = 0, totalWrong = 0;
        sessions.forEach(s => { totalQuestions += (s.total_questions || 0); totalCorrect += (s.correct_count || 0); totalWrong += (s.wrong_count || 0); });
        const accuracy = totalQuestions > 0 ? Math.round((totalCorrect / totalQuestions) * 100) : 0;

        const todayStr = new Date().toISOString().split('T')[0];
        const todaySessions = sessions.filter(s => s.created_at?.startsWith(todayStr));
        let dailyAttempts = 0, dailyCorrect = 0, dailyWrong = 0, dailyTimeTotal = 0;

        todaySessions.forEach(s => { dailyAttempts += (s.total_questions || 0); dailyCorrect += (s.correct_count || 0); dailyWrong += (s.wrong_count || 0); dailyTimeTotal += (s.time_taken_seconds || 0); });
        const dailyAvgTime = dailyAttempts > 0 ? Math.round(dailyTimeTotal / dailyAttempts) : 0;

        const history: TestHistoryItem[] = sessions.slice(0, 20).map((s: any) => ({
            id: s.id, subject: s.subject || 'General', correct: s.correct_count, totalQuestions: s.total_questions, timeTaken: s.time_taken_seconds, date: s.created_at, type: s.test_type
        }));

        const graphMap = new Map<string, number>();
        [...Array(7)].map((_, i) => { const d = new Date(); d.setDate(d.getDate() - i); return d.toISOString().split('T')[0]; }).reverse().forEach(d => graphMap.set(d.slice(5), 0));

        sessions.forEach(s => {
            const dateKey = s.created_at.slice(5, 10);
            if (graphMap.has(dateKey)) graphMap.set(dateKey, (graphMap.get(dateKey) || 0) + (s.correct_count || 0));
        });

        return { totalQuestions, totalCorrect, totalWrong, accuracy, dailyAttempts, dailyCorrect, dailyWrong, dailyAvgTime, totalTests: sessions.length, history, graphData: Array.from(graphMap.entries()).map(([day, score]) => ({ day, score })) };
    } catch (e) { return { totalQuestions: 0, totalCorrect: 0, totalWrong: 0, accuracy: 0, dailyAttempts: 0, dailyCorrect: 0, dailyWrong: 0, dailyAvgTime: 0, totalTests: 0, history: [], graphData: [] }; }
  },

  getChapterStats: async (subject: string): Promise<{ en: string, hi: string, count: number }[]> => {
      try {
          // STRICT SORTING: Order by ID to ensure chapters appear in book order
          const { data } = await supabase
            .from('questions')
            .select('chapter_name_en, chapter_name_hi, id')
            .eq('subject', subject)
            .order('id', { ascending: true });

          if (!data) return [];
          const map = new Map<string, { en: string, hi: string, count: number }>();

          // Map preserves insertion order, so sorting by ID first guarantees correct Chapter order
          data.forEach((q: any) => {
              const en = q.chapter_name_en;
              const hi = q.chapter_name_hi || '';
              if (!map.has(en)) map.set(en, { en, hi, count: 0 });
              map.get(en)!.count++;
          });
          return Array.from(map.values());
      } catch (e) { return []; }
  },

  createPracticeSession: async (userId: string, subject: string, chapters: string[]) => 'session-' + Date.now(),

  fetchInfinityBatch: async (chapters: string[], seenIds: number[], qty: number): Promise<Question[]> => {
    if (!chapters.length) return [];
    try {
        const promises = chapters.map(async (chapterName) => {
            let query = supabase.from('questions').select('*').eq('chapter_name_en', chapterName);
            if (seenIds.length > 0) query = query.not('id', 'in', `(${seenIds.join(',')})`);
            const { data } = await query.limit(qty);
            return data as Question[] || [];
        });
        const results = await Promise.all(promises);
        const all = results.flat();
        for (let i = all.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [all[i], all[j]] = [all[j], all[i]]; }
        return all;
    } catch (e) { return []; }
  },

  getPYQs: async (subject: string, year: number, type: string): Promise<PYQQuestion[]> => {
    const { data } = await supabase.from('pyq_questions').select('*').eq('subject', subject).eq('exam_year', year).eq('question_type', type);
    return data as PYQQuestion[] || [];
  }
};

