  onExit: () => void;
  defaultLanguage?: 'Hindi' | 'English';
}

// --- HELPER COMPONENT: Smart Text Formatter ---
const FormattedText = ({ text, className, style }: { text: string; className?: string; style?: React.CSSProperties }) => {
  if (!text) return null;
  const lines = text.split('\n');

  return (
    <div className={`space-y-3 font-serif ${className}`} style={style}>
      {lines.map((line, index) => {
        const trimmed = line.trim();
        if (!trimmed) return <div key={index} className="h-2" />; // Spacer for empty lines

        // 1. Handle Bullet Points (e.g., "- Point", "• Point")
        if (trimmed.startsWith('•') || trimmed.startsWith('-') || trimmed.startsWith('*')) {
          const content = trimmed.replace(/^[•\-*]\s*/, '');
          return (
            <div key={index} className="flex gap-3 pl-2">
              <span className="shrink-0 text-slate-400 dark:text-slate-500 font-bold mt-1.5 w-1.5 h-1.5 rounded-full bg-current block"></span>
              <span className="leading-relaxed">{content}</span>
            </div>
          );
        }

        // 2. Handle Numbered Lists (e.g., "1. Point", "10. Point")
        const numberMatch = trimmed.match(/^(\d+)\.\s+(.*)/);
        if (numberMatch) {
          return (
            <div key={index} className="flex gap-3 pl-2">
              <span className="shrink-0 font-bold text-slate-500 dark:text-slate-400 min-w-[1.5rem]">{numberMatch[1]}.</span>
              <span className="leading-relaxed">{numberMatch[2]}</span>
            </div>
          );
        }

        // 3. Standard Paragraph
        return <p key={index} className="leading-loose text-justify text-slate-800 dark:text-slate-200">{line}</p>;
      })}
    </div>
  );
};

