                                    const isSelected = formData.examLanguage === lang;
                                    return (
                                        <div 
                                            key={lang}
                                            onClick={() => setFormData({...formData, examLanguage: lang as any})}
                                            className={`p-4 rounded-2xl border cursor-pointer transition-all flex items-center justify-between active:scale-[0.98] ${isSelected ? 'border-brand-500 bg-slate-50 dark:bg-slate-800 shadow-lg shadow-brand-200 dark:shadow-brand-900/50 ring-1 ring-brand-500' : 'border-transparent bg-white dark:bg-slate-900 shadow-sm hover:bg-slate-50 dark:hover:bg-slate-800'}`}
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className={`w-10 h-10 rounded-xl flex items-center justify-center transition-colors ${isSelected ? 'bg-brand-500 text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-400'}`}>
                                                    <Languages size={20} />
                                                </div>
                                                <div>
                                                    <h3 className={`font-bold text-lg ${isSelected ? 'text-slate-900 dark:text-white' : 'text-slate-500 dark:text-slate-400'}`}>{lang}</h3>
                                                </div>
                                            </div>
                                            {isSelected && <div className="w-5 h-5 bg-brand-500 rounded-full flex items-center justify-center"><div className="w-2 h-2 bg-white rounded-full"></div></div>}
                                        </div>
                                    )
                                })}
                            </div>
                        </motion.div>
                    )}

                </AnimatePresence>
            </div>

            {error && (
                <div className="mb-4 text-center">
                    <p className="text-red-500 dark:text-red-400 text-xs font-bold bg-red-50 dark:bg-red-950/30 py-2 px-4 rounded-full inline-block shadow-sm border border-red-200 dark:border-red-900/50 animate-pulse">{error}</p>
                </div>
            )}

            <div className="flex items-center gap-4 mt-auto z-30 pb-4">
                 {step > 1 && (
                    <button 
                        onClick={handleAppBack}
                        className="w-14 h-14 rounded-full bg-white dark:bg-slate-900 shadow-md text-slate-400 flex items-center justify-center hover:text-slate-900 dark:hover:text-white transition-colors border border-slate-200 dark:border-slate-800"
                    >
                        <ChevronLeft size={24} />
                    </button>
                 )}

                 <button 
                    onClick={step < 4 ? handleNext : handleSubmit}
                    disabled={
                        (step === 1 && !formData.fullName) || 
                        (step === 2 && !formData.location) || 
                        (step === 3 && formData.mobileNumber.length < 10) ||
                        loading
                    }
                    className="flex-1 h-14 bg-slate-900 dark:bg-white text-white dark:text-slate-950 rounded-full font-bold text-lg shadow-xl shadow-slate-900/10 dark:shadow-white/10 disabled:opacity-50 disabled:cursor-not-allowed hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-2"
                 >
                    {loading ? <Loader2 className="animate-spin" /> : (
                        step < 4 ? (
                            <>Next <ArrowRight size={20} /></>
                        ) : (
                            <>Start Learning <Sparkles size={18} /></>
                        )
                    )}
                 </button>
            </div>

        </div>
    </div>
  );
};

