interface PYQSubjectiveScreenProps {
  subject: string;
  year: number;
  onExit: () => void;
  defaultLanguage?: 'Hindi' | 'English';
}

// --- HELPER COMPONENT: Smart Text Formatter (Book Style) ---
const FormattedText = ({ text, style }: { text: string; style?: React.CSSProperties }) => {
  if (!text) return null;
  const lines = text.split('\n');

  return (
    <div className="space-y-4 font-serif text-slate-800 dark:text-slate-200" style={style}>
      {lines.map((line, index) => {
        const trimmed = line.trim();
        if (!trimmed) return <div key={index} className="h-2" />; // Spacer

        // 1. Detect Math/Formulas (Simple heuristic: contains =, =>, or common math symbols)
        const isMath = /[=≈→⇒∫∑√θπ]/.test(trimmed) && trimmed.length < 50;
        if (isMath) {
            return (
                <div key={index} className="flex justify-center my-4">
                    <span className="font-mono bg-slate-100 dark:bg-slate-800 px-4 py-2 rounded-lg text-slate-900 dark:text-white font-medium italic">
                        {trimmed}
                    </span>
                </div>
            );
        }

        // 2. Handle Headers (Ends with :)
        if (trimmed.endsWith(':')) {
            return (
                <h4 key={index} className="font-bold text-brand-700 dark:text-brand-400 mt-6 mb-2 text-lg">
                    {trimmed}
                </h4>
            );
        }

        // 3. Handle Bullet Points / Numbering -> Convert to "Paragraph Blocks"
        // Regex looks for "1.", "(a)", "-", "•" at the start
        const listMatch = trimmed.match(/^(\d+\.|[a-z]\)|\-|•|\*)\s+(.*)/);
        if (listMatch) {
          return (
            <div key={index} className="flex gap-4 mb-4 group">
               {/* Bullet/Number Marker */}
               <div className="shrink-0 mt-1.5 w-6 flex justify-center">
                    <span className="text-brand-500 font-bold text-sm bg-brand-50 dark:bg-brand-900/30 px-1.5 rounded">
                        {listMatch[1].replace(/[•\-*]/, '•')}
                    </span>
               </div>
               {/* Content - Treated as a paragraph block */}
               <p className="leading-8 text-justify opacity-90 group-hover:opacity-100 transition-opacity">
                   {listMatch[2]}
               </p>
            </div>
          );
        }

        // 4. Standard Paragraph
        return (
            <p key={index} className="leading-8 text-justify opacity-90 mb-4">
                {line}
            </p>
        );
      })}
    </div>
  );
};

export const PYQSubjectiveScreen: React.FC<PYQSubjectiveScreenProps> = ({ 
    subject, 
    year, 
    onExit,
    defaultLanguage 
}) => {
  const [questions, setQuestions] = useState<PYQQuestion[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentIndex, setCurrentIndex] = useState(0);

  const [lang, setLang] = useState<Language>(() => {
    if (defaultLanguage) return defaultLanguage === 'Hindi' ? 'hi' : 'en';
    const stored = localStorage.getItem('raftaar-language');
    if (stored === 'hi' || stored === 'en') return stored as Language;
    return 'en';
  });

  const [fontSize, setFontSize] = useState(18); // Default font size increased for book feel

  // Sync prop changes
  useEffect(() => {
    if (defaultLanguage) {
      setLang(defaultLanguage === 'Hindi' ? 'hi' : 'en');
    }
  }, [defaultLanguage]);

  // Handle Back
  useBackHandler(() => {
    onExit(); 
    return true;
  });

  // Fetch Data with Safe Mounting Check
  useEffect(() => {
    let isMounted = true;
    const fetchQuestions = async () => {
        setLoading(true);
        try {
            const data = await api.getPYQs(subject, year, 'subjective');
            if (isMounted) {
                setQuestions(data || []);
            }
        } catch (e) {
            console.error(e);
            if (isMounted) setQuestions([]);
        } finally {
            if (isMounted) setLoading(false);
        }
    };
    if (subject && year) {
        fetchQuestions();
    }
    return () => { isMounted = false; };
  }, [subject, year]);

  // Safe Current Question derivation
  const currentQ = (questions && questions.length > 0) ? questions[currentIndex] : null;

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      onExit();
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  // Robust Text Helper
  const getTxt = (en?: string | null, hi?: string | null) => {
      if (!en && !hi) return "";
      return lang === 'hi' ? (hi || en || "") : (en || "");
  };

  if (loading) {
      return (
        <div className="h-[100dvh] flex flex-col items-center justify-center bg-[#fdfbf7] dark:bg-slate-950 gap-4 transition-colors">
            <div className="w-10 h-10 border-4 border-slate-800 dark:border-slate-200 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-slate-500 dark:text-slate-400 font-serif italic text-sm animate-pulse">Opening Book...</p>
        </div>
      );
  }

  // Safe Null Check for Question Data
  if (!currentQ) {
    return (
      <div className="h-[100dvh] flex flex-col items-center justify-center bg-[#fdfbf7] dark:bg-slate-950 transition-colors p-6 text-center">
        <p className="text-slate-500 dark:text-slate-400 font-serif mb-4">No notes found for {subject} {year}.</p>
        <button onClick={onExit} className="px-6 py-2 bg-slate-900 dark:bg-slate-100 rounded-lg text-sm font-bold text-white dark:text-slate-900 shadow-sm">Close Book</button>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] flex flex-col bg-[#fdfbf7] dark:bg-slate-950 font-serif animate-fade-in text-slate-900 dark:text-white transition-colors duration-300">

      {/* Header (Minimal) */}
      <div className="px-4 pb-3 pt-safe-header bg-[#fdfbf7] dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800 flex justify-between items-center sticky top-0 z-50 transition-colors">
        <div className="flex items-center gap-3">
          <button onClick={onExit} className="p-2 -ml-2 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors">
            <ArrowLeft size={22} />
          </button>
          <div>
            <h2 className="text-lg font-bold text-slate-900 dark:text-white leading-none font-sans">Subjective</h2>
            <p className="text-[10px] font-bold text-slate-500 dark:text-slate-500 uppercase mt-1 font-sans">{subject} • {year}</p>
          </div>
        </div>

        <div className="flex items-center bg-white dark:bg-slate-900 rounded-full border border-slate-200 dark:border-slate-800 p-1 shadow-sm">
          <button 
            onClick={() => setFontSize(s => Math.max(14, s - 2))}
            className="p-2 text-slate-400 hover:text-slate-900 dark:hover:text-white transition-all"
          >
            <ZoomOut size={16} />
          </button>
          <div className="w-[1px] h-4 bg-slate-200 dark:bg-slate-800 mx-1"></div>
          <button 
            onClick={() => setFontSize(s => Math.min(28, s + 2))}
            className="p-2 text-slate-400 hover:text-slate-900 dark:hover:text-white transition-all"
          >
            <ZoomIn size={16} />
          </button>
        </div>
      </div>

      {/* Top Bar (Progress & Language) - Font Sans for UI elements */}
      <div className="px-5 py-3 flex justify-between items-center bg-[#fdfbf7] dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800 transition-colors shrink-0 font-sans">
        <div className="flex gap-1 overflow-x-auto hide-scrollbar max-w-[200px]">
            {questions.map((_, idx) => (
                <div 
                    key={idx} 
                    className={`h-1.5 rounded-full transition-all duration-300 shrink-0 ${idx === currentIndex ? 'w-6 bg-slate-900 dark:bg-white' : 'w-1.5 bg-slate-300 dark:bg-slate-700'}`}
                />
            ))}
        </div>
        <button 
            onClick={() => setLang(l => l === 'en' ? 'hi' : 'en')} 
            className="flex items-center gap-1.5 bg-white dark:bg-slate-900 px-3 py-1.5 rounded-full border border-slate-200 dark:border-slate-700 text-[10px] font-bold text-slate-700 dark:text-slate-300 shadow-sm shrink-0 active:scale-95 transition-transform"
        >
            <BookOpen size={12} />
            {lang === 'en' ? 'ENGLISH' : 'HINDI'}
        </button>
      </div>

      {/* Content Area - THE MAIN BOOK VIEW */}
      <div className="flex-1 overflow-y-auto w-full bg-[#fdfbf7] dark:bg-slate-950 transition-colors pb-32">
        <div className="max-w-2xl mx-auto p-5 sm:p-8">

            {/* QUESTION */}
            <div className="mb-8">
                <div className="flex items-center justify-between mb-4 font-sans">
                    <span className="text-slate-500 font-bold text-xs uppercase tracking-widest flex items-center gap-2">
                        <Hash size={12} /> Question {currentIndex + 1}
                    </span>
                    {currentQ?.marks && (
                        <span className="bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 px-2 py-1 rounded text-[10px] font-bold border border-slate-200 dark:border-slate-700">
                            {currentQ.marks} Marks
                        </span>
                    )}
                </div>

                <h1 
                    className="font-bold text-slate-900 dark:text-white leading-tight font-serif break-words select-text"
                    style={{ fontSize: `${fontSize + 4}px` }}
                >
                    {getTxt(currentQ?.question_text_en, currentQ?.question_text_hi)}
                </h1>
            </div>

            {/* DIVIDER */}
            <div className="flex items-center justify-center my-8 opacity-20">
                <div className="h-[1px] w-full bg-slate-900 dark:bg-white"></div>
                <div className="mx-4 text-slate-900 dark:text-white font-serif italic text-lg">Answer</div>
                <div className="h-[1px] w-full bg-slate-900 dark:bg-white"></div>
            </div>

            {/* ANSWER (Notes Style) */}
            <div className="relative">
                {/* Visual Indicator on Left */}
                <div className="absolute -left-3 top-2 bottom-2 w-[2px] bg-brand-500/20 dark:bg-brand-400/20 rounded-full"></div>

                <div className="select-text pl-2">
                    <FormattedText 
                        text={getTxt(currentQ?.answer_text_en, currentQ?.answer_text_hi) || getTxt(currentQ?.solution_short_en, currentQ?.solution_short_hi) || "Detailed answer not available."} 
                        style={{ fontSize: `${fontSize}px` }}
                    />
                </div>
            </div>

            {/* "End of Note" symbol */}
            <div className="flex justify-center mt-12 mb-4 opacity-30">
                <span className="text-xl tracking-[0.5em] text-slate-400">•••</span>
            </div>

        </div>
      </div>

      {/* Bottom Navigation */}
      <div className="fixed bottom-0 w-full bg-[#fdfbf7]/95 dark:bg-slate-950/95 backdrop-blur-sm border-t border-slate-200 dark:border-slate-800 p-4 pb-safe z-30 flex gap-4 transition-colors font-sans">
        <button 
            onClick={handlePrev}
            disabled={currentIndex === 0}
            className="flex-1 py-3.5 rounded-xl font-bold text-slate-600 dark:text-slate-400 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors active:bg-slate-50 dark:active:bg-slate-800 shadow-sm hover:shadow-md"
        >
            Previous
        </button>
        <button 
            onClick={handleNext}
            className="flex-1 py-3.5 rounded-xl font-bold text-white bg-slate-900 dark:bg-slate-100 dark:text-slate-950 shadow-lg hover:scale-[1.02] transition-transform active:scale-[0.98]"
        >
            {currentIndex === questions.length - 1 ? 'Finish' : 'Next'}
        </button>
      </div>

    </div>
  );
};

