import { supabase } from './supabase';
import { Profile, Question, TestSubmission, LeaderboardEntry, SubjectStats, ChapterStats, PYQYear, PYQQuestion } from '../types';

export const api = {
  // ... (existing methods like getSubjects, getChapters remain same)

  async registerOrLogin({ fullName, mobileNumber, location, examLanguage }: { fullName: string, mobileNumber: string, location: string, examLanguage: 'Hindi' | 'English' }) {
