import { useBackHandler } from '../hooks/useBackHandler';

interface PYQSubjectiveScreenProps {
  subject: string;
  year: number;
  onExit: () => void;
  defaultLanguage?: 'Hindi' | 'English';
}

// --- HELPER COMPONENT: Smart Text Formatter (Book Style) ---
const FormattedText = ({ text, style }: { text: string; style?: React.CSSProperties }) => {
  if (!text) return null;
  const lines = text.split('\n');

  return (
    <div className="space-y-4 font-serif text-slate-800 dark:text-slate-200" style={style}>
      {lines.map((line, index) => {
        const trimmed = line.trim();
        if (!trimmed) return <div key={index} className="h-2" />; // Spacer

        // 1. Detect Math/Formulas (Simple heuristic: contains =, =>, or common math symbols)
        const isMath = /[=≈→⇒∫∑√θπ]/.test(trimmed) && trimmed.length < 50;
        if (isMath) {
            return (
                <div key={index} className="flex justify-center my-4">
                    <span className="font-mono bg-slate-100 dark:bg-slate-800 px-4 py-2 rounded-lg text-slate-900 dark:text-white font-medium italic">
                        {trimmed}
                    </span>
                </div>
            );
        }

        // 2. Handle Headers (Ends with :)
        if (trimmed.endsWith(':')) {
            return (
                <h4 key={index} className="font-bold text-brand-700 dark:text-brand-400 mt-6 mb-2 text-lg">
                    {trimmed}
                </h4>
            );
        }

        // 3. Handle Bullet Points / Numbering -> Convert to "Paragraph Blocks"
        // Regex looks for "1.", "(a)", "-", "•" at the start
        const listMatch = trimmed.match(/^(\d+\.|[a-z]\)|\-|•|\*)\s+(.*)/);
        if (listMatch) {
          return (
            <div key={index} className="flex gap-4 mb-4 group">
               {/* Bullet/Number Marker */}
               <div className="shrink-0 mt-1.5 w-6 flex justify-center">
                    <span className="text-brand-500 font-bold text-sm bg-brand-50 dark:bg-brand-900/30 px-1.5 rounded">
                        {listMatch[1].replace(/[•\-*]/, '•')}
                    </span>
               </div>
               {/* Content - Treated as a paragraph block */}
               <p className="leading-8 text-justify opacity-90 group-hover:opacity-100 transition-opacity">
                   {listMatch[2]}
               </p>
            </div>
          );
        }

        // 4. Standard Paragraph
        return (
            <p key={index} className="leading-8 text-justify opacity-90 mb-4">
                {line}
            </p>
        );
      })}
    </div>
  );
};

export const PYQSubjectiveScreen: React.FC<PYQSubjectiveScreenProps> = ({ 
    subject, 
    year, 
    onExit,
    defaultLanguage 
}) => {
  const [questions, setQuestions] = useState<PYQQuestion[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentIndex, setCurrentIndex] = useState(0);

  const [lang, setLang] = useState<Language>(() => {
    if (defaultLanguage) return defaultLanguage === 'Hindi' ? 'hi' : 'en';
    const stored = localStorage.getItem('raftaar-language');
    if (stored === 'hi' || stored === 'en') return stored as Language;
    return 'en';
  });

  const [fontSize, setFontSize] = useState(18); // Default font size increased for book feel

  // Sync prop changes
  useEffect(() => {
    if (defaultLanguage) {
      setLang(defaultLanguage === 'Hindi' ? 'hi' : 'en');
    }
  }, [defaultLanguage]);

  // Handle Back
  useBackHandler(() => {
    onExit(); 
    return true;
  });

  // Fetch Data with Safe Mounting Check
  useEffect(() => {
    let isMounted = true;
    const fetchQuestions = async () => {
        setLoading(true);
        try {
            const data = await api.getPYQs(subject, year, 'subjective');
            if (isMounted) {
                setQuestions(data || []);
            }
        } catch (e) {
            console.error(e);
            if (isMounted) setQuestions([]);
        } finally {
            if (isMounted) setLoading(false);
        }
    };
    if (subject && year) {
        fetchQuestions();
    }
    return () => { isMounted = false; };
  }, [subject, year]);

  // Safe Current Question derivation
  const currentQ = (questions && questions.length > 0) ? questions[currentIndex] : null;

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      onExit();
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  // Robust Text Helper
  const getTxt = (en?: string | null, hi?: string | null) => {
      if (!en && !hi) return "";
      return lang === 'hi' ? (hi || en || "") : (en || "");
  };

  if (loading) {
      return (
        <div className="h-[100dvh] flex flex-col items-center justify-center bg-[#fdfbf7] dark:bg-slate-950 gap-4 transition-colors">
