        <button onClick={onExit} className="px-6 py-2 bg-slate-900 dark:bg-slate-100 rounded-lg text-sm font-bold text-white dark:text-slate-900 shadow-sm">Close Book</button>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] flex flex-col bg-[#fdfbf7] dark:bg-slate-950 font-serif animate-fade-in text-slate-900 dark:text-white transition-colors duration-300">

      {/* Header (Minimal) */}
      <div className="px-4 pb-3 pt-safe-header bg-[#fdfbf7] dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800 flex justify-between items-center sticky top-0 z-50 transition-colors">
