          </div>
        </div>

        <div className="flex items-center bg-white dark:bg-slate-900 rounded-full border border-slate-200 dark:border-slate-800 p-1 shadow-sm">
          <button 
            onClick={() => setFontSize(s => Math.max(14, s - 2))}
