// --- HELPER COMPONENT: Smart Text Formatter (Standard Style) ---
const FormattedText = ({ text, style }: { text: string; style?: React.CSSProperties }) => {
  if (!text) return null;
  const lines = text.split('\n');

  return (
    <div className="space-y-4 font-sans text-slate-700 dark:text-slate-300" style={style}>
      {lines.map((line, index) => {
        const trimmed = line.trim();
        if (!trimmed) return <div key={index} className="h-2" />; // Spacer

        // 1. Detect Math/Formulas
        const isMath = /[=≈→⇒∫∑√θπ]/.test(trimmed) && trimmed.length < 50;
        if (isMath) {
            return (
                <div key={index} className="flex justify-center my-4">
                    <span className="font-mono bg-slate-100 dark:bg-slate-800 px-4 py-2 rounded-lg text-slate-900 dark:text-white font-medium">
                        {trimmed}
                    </span>
                </div>
            );
        }

        // 2. Handle Headers (Ends with :)
        if (trimmed.endsWith(':')) {
            return (
                <h4 key={index} className="font-bold text-slate-900 dark:text-white mt-6 mb-2 text-lg">
                    {trimmed}
                </h4>
            );
        }

        // 3. Handle Bullet Points
        const listMatch = trimmed.match(/^(\d+\.|[a-z]\)|\-|•|\*)\s+(.*)/);
        if (listMatch) {
          return (
            <div key={index} className="flex gap-4 mb-4">
               {/* Bullet/Number Marker */}
               <div className="shrink-0 mt-1 w-6 flex justify-center">
                    <span className="text-slate-500 font-bold text-sm bg-slate-100 dark:bg-slate-800 px-1.5 rounded">
                        {listMatch[1].replace(/[•\-*]/, '•')}
                    </span>
               </div>
               {/* Content */}
               <p className="leading-relaxed text-justify">
                   {listMatch[2]}
               </p>
            </div>
          );
        }

        // 4. Standard Paragraph
        return (
            <p key={index} className="leading-relaxed text-justify mb-4">
                {line}
            </p>
        );
      })}
    </div>
  );
};

export const PYQSubjectiveScreen: React.FC<PYQSubjectiveScreenProps> = ({ 
    subject, 
    year, 
    onExit,
    defaultLanguage = 'English' 
}) => {
  const [questions, setQuestions] = useState<PYQQuestion[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentIndex, setCurrentIndex] = useState(0);

  // ✅ 1. Initialize State from Local Storage
  const [lang, setLang] = useState<Language>(() => {
    const saved = localStorage.getItem('raftaar-language');
    if (saved === 'Hindi' || saved === 'hi') return 'hi';
    if (saved === 'English' || saved === 'en') return 'en';
    return defaultLanguage === 'Hindi' ? 'hi' : 'en';
  });

  // ✅ 2. Toggle Handler
  const toggleLanguage = () => {
    setLang(prev => {
      const newLang = prev === 'en' ? 'hi' : 'en';
      localStorage.setItem('raftaar-language', newLang === 'hi' ? 'Hindi' : 'English');
      return newLang;
    });
  };

  const [fontSize, setFontSize] = useState(16); // Default standard size

  // Handle Back
  useBackHandler(() => {
    onExit(); 
    return true;
  });

  // Fetch Data with Safe Mounting Check
  useEffect(() => {
    let isMounted = true;
    const fetchQuestions = async () => {
        setLoading(true);
        try {
            const data = await api.getPYQs(subject, year, 'subjective');
            if (isMounted) {
                setQuestions(data || []);
            }
        } catch (e) {
            console.error(e);
            if (isMounted) setQuestions([]);
        } finally {
            if (isMounted) setLoading(false);
        }
    };
    if (subject && year) {
        fetchQuestions();
    }
    return () => { isMounted = false; };
  }, [subject, year]);

  // Safe Current Question derivation
  const currentQ = (questions && questions.length > 0) ? questions[currentIndex] : null;

  const handleNext = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      onExit();
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  // Robust Text Helper
  const getTxt = (en?: string | null, hi?: string | null) => {
      if (!en && !hi) return "";
      return lang === 'hi' ? (hi || en || "") : (en || "");
  };

  if (loading) {
      return (
        <div className="h-[100dvh] flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950 gap-4 transition-colors">
            <div className="w-10 h-10 border-4 border-slate-200 dark:border-slate-800 border-t-brand-500 rounded-full animate-spin"></div>
            <p className="text-slate-500 dark:text-slate-400 font-bold text-xs uppercase tracking-widest animate-pulse">Loading Notes...</p>
        </div>
      );
  }

  // Safe Null Check for Question Data
  if (!currentQ) {
    return (
      <div className="h-[100dvh] flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950 transition-colors p-6 text-center">
        <p className="text-slate-500 dark:text-slate-400 font-medium mb-4">No notes found for {subject} {year}.</p>
        <button onClick={onExit} className="px-6 py-2 bg-slate-900 dark:bg-white rounded-lg text-sm font-bold text-white dark:text-slate-900 shadow-sm">Go Back</button>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] flex flex-col bg-slate-50 dark:bg-slate-950 font-sans animate-fade-in text-slate-900 dark:text-white transition-colors duration-300">

      {/* Header (Minimal) */}
      <div className="px-4 pb-3 pt-safe-header bg-white dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800 flex justify-between items-center sticky top-0 z-50 transition-colors">
        <div className="flex items-center gap-3">
          <button onClick={onExit} className="p-2 -ml-2 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-900 rounded-full transition-colors">
            <ArrowLeft size={20} />
          </button>
          <div>
            <h2 className="text-lg font-black text-slate-900 dark:text-white leading-none">Subjective</h2>
            <p className="text-[10px] font-bold text-slate-500 dark:text-slate-500 uppercase mt-1">{subject} • {year}</p>
          </div>
        </div>

        <div className="flex items-center bg-slate-100 dark:bg-slate-900 rounded-full border border-slate-200 dark:border-slate-800 p-1">
          <button 
            onClick={() => setFontSize(s => Math.max(14, s - 2))}
            className="p-2 text-slate-400 hover:text-slate-900 dark:hover:text-white transition-all"
          >
            <ZoomOut size={16} />
          </button>
          <div className="w-[1px] h-4 bg-slate-300 dark:bg-slate-700 mx-1"></div>
          <button 
            onClick={() => setFontSize(s => Math.min(24, s + 2))}
            className="p-2 text-slate-400 hover:text-slate-900 dark:hover:text-white transition-all"
          >
            <ZoomIn size={16} />
          </button>
        </div>
      </div>

      {/* Top Bar (Progress & Language) */}
      <div className="px-5 py-3 flex justify-between items-center bg-slate-50 dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800 transition-colors shrink-0">
        <div className="flex gap-1 overflow-x-auto hide-scrollbar max-w-[200px]" style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}>
            {questions.map((_, idx) => (
                <div 
                    key={idx} 
                    className={`h-1 rounded-full transition-all duration-300 shrink-0 ${idx === currentIndex ? 'w-6 bg-slate-900 dark:bg-white' : 'w-1.5 bg-slate-300 dark:bg-slate-700'}`}
                />
            ))}
        </div>

        {/* ✅ 3. Update Toggle Button */}
        <button 
            onClick={toggleLanguage} 
            className="flex items-center gap-1.5 bg-white dark:bg-slate-900 px-3 py-1.5 rounded-full border border-slate-200 dark:border-slate-800 text-[10px] font-bold text-slate-600 dark:text-slate-400 shadow-sm shrink-0 active:scale-95 transition-transform"
        >
            <BookOpen size={12} />
            {lang === 'en' ? 'ENGLISH' : 'HINDI'}
        </button>
      </div>

      {/* Content Area - Standard View */}
      <div 
        className="flex-1 overflow-y-auto w-full bg-slate-50 dark:bg-slate-950 transition-colors pb-32 hide-scrollbar"
        style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
      >
        <div className="max-w-2xl mx-auto p-5">

            {/* QUESTION CARD */}
            <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm mb-6">
                <div className="flex items-center justify-between mb-4">
                    <span className="text-slate-400 font-bold text-[10px] uppercase tracking-wider flex items-center gap-2">
                        <Hash size={12} /> Question {currentIndex + 1}
                    </span>
                    {currentQ?.marks && (
                        <span className="bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400 px-2 py-1 rounded text-[10px] font-bold border border-slate-200 dark:border-slate-700">
                            {currentQ.marks} Marks
                        </span>
                    )}
                </div>

                <h1 
                    className="font-bold text-slate-900 dark:text-white leading-relaxed break-words"
                    style={{ fontSize: `${fontSize + 2}px` }}
                >
                    {getTxt(currentQ?.question_text_en, currentQ?.question_text_hi)}
                </h1>
            </div>

            {/* ANSWER CARD */}
            <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm relative overflow-hidden">
                <div className="absolute top-0 left-0 w-1 h-full bg-brand-500"></div>

                <div className="flex items-center gap-2 mb-4">
                    <div className="w-6 h-6 rounded-full bg-green-100 dark:bg-green-900/30 flex items-center justify-center text-green-600 dark:text-green-400">
                        <CheckCircle size={14} />
                    </div>
                    <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Model Answer</h3>
                </div>

                <div className="select-text">
                    <FormattedText 
                        text={getTxt(currentQ?.answer_text_en, currentQ?.answer_text_hi) || getTxt(currentQ?.solution_short_en, currentQ?.solution_short_hi) || "Detailed answer not available."} 
                        style={{ fontSize: `${fontSize}px` }}
                    />
                </div>
            </div>

            <div className="flex justify-center mt-8 opacity-30">
                <div className="w-12 h-1 bg-slate-200 dark:bg-slate-800 rounded-full"></div>
            </div>

        </div>
      </div>

      {/* Bottom Navigation */}
      <div className="fixed bottom-0 w-full bg-white dark:bg-slate-950 border-t border-slate-200 dark:border-slate-800 p-4 pb-safe z-30 flex gap-4 transition-colors">
        <button 
            onClick={handlePrev}
            disabled={currentIndex === 0}
            className="flex-1 py-3.5 rounded-xl font-bold text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 disabled:opacity-50 disabled:cursor-not-allowed transition-colors active:scale-95"
        >
            Previous
        </button>
        <button 
            onClick={handleNext}
            className="flex-1 py-3.5 rounded-xl font-bold text-white bg-slate-900 dark:bg-white dark:text-slate-950 shadow-lg hover:scale-[1.02] transition-transform active:scale-[0.98]"
        >
            {currentIndex === questions.length - 1 ? 'Finish' : 'Next'}
        </button>
